window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["map"]={"updatedAt":"2026-07-06","count":280,"nodes":[{"id":"nha-to-cua-huyen-gia","name":"Nhà Tổ của Huyễn gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Địa điểm trên Thiên Huyễn Tinh, nơi Huyễn gia Lão Tổ đang bế quan. Kiếm khí của Lăng Thiên Hầu truy kích qua lốc xoáy đã chấn động tới nơi này.","detail":"Nhà Tổ của Huyễn gia là nơi Huyễn gia Lão Tổ khoanh chân bế quan trong phòng có lốc xoáy trước mặt. Sau khi lão cứu Liễu Mi, kiếm khí của Lăng Thiên Hầu do Vương Lâm phóng ra truy kích đến đây, khiến lốc xoáy sụp đổ và lão phát ra tiếng kêu đau.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0635"]},{"id":"mat-that-cua-huyen-gia-lao-to","name":"Mật thất của Huyễn gia Lão Tổ","cn":"","capDo":"khac","parentId":"nha-to-cua-huyen-gia","blurb":"Căn mật thất trong Nhà Tổ Huyễn gia, nơi bạch quang cuốn Liễu Mi trở về sau khi thoát khỏi Vương Lâm. Bạch quang sau đó chui vào mi tâm Huyễn gia Lão Tổ.","detail":"Mật thất của Huyễn gia Lão Tổ nằm trong khu vực Nhà Tổ Huyễn gia trên Thiên Huyễn Tinh. Sau khi lốc xoáy cứu viện sụp đổ, bạch quang cuốn Liễu Mi vào căn phòng này, ném nàng sang một bên rồi nhập vào mi tâm Huyễn gia Lão Tổ.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0635"]},{"id":"tinh-khong","name":"Tinh không","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian rộng lớn giữa các tinh cầu, nơi Huyễn gia Lão Tổ dùng nguyên thần vượt qua để cứu Liễu Mi.","detail":"Trong chương này, Huyễn gia Lão Tổ dùng nguyên thần vượt tinh không để cứu Liễu Mi khỏi Vương Lâm. Kiếm khí của Lăng Thiên Hầu cũng truy theo thông đạo, khiến lão hoảng hốt tháo chạy về mật thất.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0636"]},{"id":"toa-tinh-dai-tran","name":"Tỏa Tinh đại trận","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Đại trận bao quanh hoặc liên quan Nhiễm Vân Tinh mà Vương Lâm xuyên qua khi rời tinh cầu.","detail":"Trước khi dùng Tinh La bàn lao vào tinh không, Vương Lâm đạp hư không và xuyên qua Tỏa Tinh đại trận, rời Nhiễm Vân Tinh để đi tới Thiên Huyễn Tinh.","theLucLienQuan":[],"nguon":["@c0637"]},{"id":"thanh-tri-xa-xa-nhiem-van-tinh","name":"Thành trì xa xa","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh","blurb":"Thành trì trên Nhiễm Vân Tinh nơi Tôn Tích ẩn mình quan sát trước khi ra gặp Vương Lâm.","detail":"Tôn Tích từ trong thành trì xa xa bay ra sau khi chứng kiến trận chiến trước đó, mang tâm trạng sợ hãi khi đối diện Vương Lâm và thú nhận chuyện cũ.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0637"]},{"id":"phia-nam-thien-huyen-tinh","name":"Phía Nam Thiên Huyễn Tinh","cn":"","capDo":"vuc","parentId":"thien-huyen-tinh","blurb":"Khu vực Huyễn gia tập trung trực hệ tộc nhân và mở hộ tộc đại trận. Vương Lâm khóa thần thức về hướng này rồi lao tới Nhà Tổ Huyễn gia.","detail":"Phía Nam Thiên Huyễn Tinh là địa bàn Huyễn gia co cụm khi biết Vương Lâm sắp tới. Hộ tộc đại trận được mở bao phủ khu vực này, còn các tu sĩ bậc cao được phái đi đón tộc nhân chưa kịp trở về.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0638"]},{"id":"phuong-bac-va-phuong-dong-thien-huyen-tinh","name":"Phương Bắc và phương Đông Thiên Huyễn Tinh","cn":"","capDo":"vuc","parentId":"thien-huyen-tinh","blurb":"Địa bàn do Thiên gia chiếm cứ trên Thiên Huyễn Tinh. Vị thế này đến từ thực lực ba lão tổ bước thứ hai của Thiên gia.","detail":"Trong thế cục ba đại gia tộc, Thiên gia mạnh nhất và chiếm phương Bắc cùng phương Đông Thiên Huyễn Tinh. Chương dùng địa bàn này để làm rõ tương quan Thiên gia vượt trên Huyễn gia và Hứa gia.","theLucLienQuan":["Thiên gia"],"nguon":["@c0638"]},{"id":"la-thien-tinh-vuc","name":"La Thiên Tinh Vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực bao gồm Thiên Huyễn Tinh và Đông Lâm Tinh. Đây cũng là không gian thế lực nơi Lôi Tiên Điện có uy danh khiến Thiên Quỳ Tử e sợ.","detail":"La Thiên Tinh Vực được nhắc qua vị trí của Đông Lâm Tinh, Thiên Huyễn Tinh và uy thế Lôi Tiên Điện. Việc Thiên Quỳ Tử nhìn thấy Lôi Thú rồi sợ hãi cho thấy Lôi Tiên Điện có ảnh hưởng rất lớn trong khu vực này.","theLucLienQuan":["Lôi Tiên Điện","Thiên gia","Huyễn gia","Hứa gia"],"nguon":["@c0638","@c0783"]},{"id":"loi-tien-gioi","name":"Lôi Tiên giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Nơi gắn với Lôi Tiên Điện, Lôi Tiên Quân và nguồn gốc Lôi Thú của Xạ Thần xa. Chương này dùng Lôi Tiên giới để giải thích vì sao Xạ Thần xa có thể hóa Lôi Thú.","detail":"Người luyện chế Xạ Thần xa từng tới Lôi Tiên giới và lấy vài đầu Lôi Thú từ Lôi Tiên Quân để luyện Thú hồn. Vì vậy Vương Lâm sở hữu Lôi Thú khiến Thiên Quỳ Tử lầm tưởng hắn là người Lôi Tiên Điện, dù Huyễn Vô Tình phủ nhận điều đó.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0638","@c0678","@c0701","@c0783"],"aliases":["Lôi Chi Tiên Giới","Lôi tiên giới"]},{"id":"vuc-sau-trieu-tich","name":"Vực sâu triều tịch","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm được nhắc trong hồi cố về kiếm khí Lăng Thiên Hậu. Vương Lâm từng lấy thêm kiếm khí dưới Vực sâu triều tịch.","detail":"Chương nhắc lại quá trình Vương Lâm có kiếm khí của Lăng Thiên Hậu: từng có hai đạo, dùng một đạo giúp Cổ Yêu, sau đó lấy thêm hai đạo dưới Vực sâu triều tịch. Nơi này không trực tiếp xuất hiện trong hiện tại chương.","theLucLienQuan":[],"nguon":["@c0638","@c0769"]},{"id":"huyen-gia-dai-tran","name":"Huyễn gia đại trận","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Huyễn gia đại trận là không gian phòng hộ bao quanh Huyễn gia trên Thiên Huyễn Tinh.","detail":"Trong chương này, các tộc nhân Huyễn gia đứng bên trong đại trận và trực tiếp chịu áp lực từ lôi uy của Lôi Thú, công kích của Tiên vệ và kiếm thức của Vương Lâm. Trận pháp bị ép đến xu hướng suy tàn nhưng trước Trảm La Quyết vẫn chưa hoàn toàn bị phá.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0639"]},{"id":"thien-gia-dia-diem","name":"Thiên gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Thiên gia là địa điểm trên Thiên Huyễn Tinh nơi Thiên Quỳ Tử quan sát biến cố Huyễn gia.","detail":"Khi Huyễn gia đại trận bị Vương Lâm công kích, Thiên Quỳ Tử ở Thiên gia quan sát diễn biến và cười lạnh trước tình thế Huyễn gia gặp nguy.","theLucLienQuan":["Thiên gia"],"nguon":["@c0639"]},{"id":"tu-duong-cua-huyen-gia","name":"Từ đường của Huyễn gia","cn":"","capDo":"khac","parentId":"nha-to-cua-huyen-gia","blurb":"Nơi Phúc Trạch ngọc giản màu vàng ngọc chậm rãi bay lên khi Huyễn Vô Tình mời chí bảo Huyễn gia ra trận.","detail":"Từ đường của Huyễn gia nằm trong phạm vi Nhà Tổ Huyễn gia. Trong chương này, Phúc Trạch ngọc giản từ nơi đây bay lên, tỏa lực lượng tường hòa và mở đầu cho việc chí bảo Huyễn gia hóa hình tấn công Vương Lâm.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0640"]},{"id":"mat-that-o-thien-gia","name":"Mật thất ở Thiên gia","cn":"","capDo":"khac","parentId":"thien-gia-dia-diem","blurb":"Nơi Thiên Quỳ Tử ngồi quan sát trận chiến Huyễn gia bằng thần thức. Ông đứng bật dậy khi nhận ra quy tắc trong kiếm thức của Vương Lâm.","detail":"Trong mật thất ở Thiên gia, Thiên Quỳ Tử dùng thần thức theo dõi biến cố tại Nhà Tổ Huyễn gia. Từ đây ông nhận ra một kiếm của Vương Lâm ẩn chứa quy tắc và suy đoán về quan hệ giữa Vương Lâm với Lôi Tiên Điện.","theLucLienQuan":["Thiên gia"],"nguon":["@c0640"]},{"id":"hua-gia-dia-diem","name":"Hứa gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Địa điểm của Hứa gia trên Thiên Huyễn Tinh, nơi lão già Hứa gia theo dõi trận chiến Huyễn gia. Ông từng định ra tay tương trợ nhưng dừng lại vì kiêng dè hậu thủ của Vương Lâm.","detail":"Từ Hứa gia, lão giả dùng thần thức quan sát Nhà Tổ Huyễn gia. Khi một kiếm của Vương Lâm phá đại trận, ông cân nhắc ước định với Huyễn gia Lão Tổ nhưng quyết định không lập tức can thiệp.","theLucLienQuan":["Hứa gia"],"nguon":["@c0640"]},{"id":"tien-nghich-khong-gian-dia-diem","name":"Tiên Nghịch không gian","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian nơi có Oán Anh mà Vương Lâm nhớ tới trong lúc đối diện Phúc Trạch ngọc giản. Đây là địa điểm đặc thù gắn với con bài của Vương Lâm.","detail":"Khi bóng người do Phúc Trạch ngọc giản hóa thành áp tới, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian. Chi tiết này dẫn vào việc hắn gọi một tồn tại trong nguyên thần và hứa thả tự do sau trận.","theLucLienQuan":["Vương Lâm"],"nguon":["@c0640"]},{"id":"yeu-linh-chi-dia","name":"Yêu Linh chi địa","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Địa điểm Vương Lâm từng chứng kiến Tham Lang dùng Tiên sơn pháp bảo rút Sơn hồn.","detail":"Trong chương này, Yêu Linh chi địa được nhắc lại như mốc so sánh: cảnh Tham Lang rút Sơn hồn bằng Tiên sơn pháp bảo kém xa quy mô Tán Ma rút tinh hồn Thiên Huyễn Tinh.","theLucLienQuan":["Tham Lang"],"nguon":["@c0642"]},{"id":"lac-nguyet-thon","name":"Lạc Nguyệt thôn","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Lạc Nguyệt thôn là sơn thôn trên Nhiễm Vân Tinh nơi Vương Lâm sống ẩn sau biến cố Huyễn gia. Tại đây hắn ở trong một căn nhà nhỏ cùng Vương Bình.","detail":"Nhiều ngày sau khi rời Huyễn gia, Vương Lâm xuất hiện tại Lạc Nguyệt thôn trong thân phận thợ mộc. Sơn thôn có đời sống phàm tục bình dị, đám trẻ tụ tập nghe chuyện Kỳ Liên Phong, còn dân thôn qua lại nhờ Vương Lâm làm đồ đạc.","theLucLienQuan":["Lạc Nguyệt thôn"],"nguon":["@c0643"]},{"id":"ky-lien-phong","name":"Kỳ Liên Phong","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Kỳ Liên Phong là ngọn núi gần Lạc Nguyệt thôn. Thiếu niên họ Chu kể nơi này từng có sương mù giúp cường thân kiện thể, nhưng đã không còn từ năm năm trước.","detail":"Trong đời sống của nhóm trẻ Lạc Nguyệt thôn, Kỳ Liên Phong là địa điểm gắn với lời kể về sương mù và luyện kiếm. Vương Bình nghe chuyện này rồi muốn nhờ cha đưa đi xem.","theLucLienQuan":["Lạc Nguyệt thôn"],"nguon":["@c0643"]},{"id":"chu-tuoc-mo","name":"Chu Tước Mộ","cn":"","capDo":"khac","parentId":"chu-tuoc-tinh","blurb":"Chu Tước Mộ là địa điểm gắn với những việc khiến Liễu Mi oán hận Vương Lâm. Chương này nhắc lại nơi ấy trong dòng hồi tưởng trước khi nàng tiêu tán.","detail":"Khi Liễu Mi nhớ lại nhân quả với Vương Lâm, Chu Tước Mộ được nhắc như một phần nguồn cơn oán hận của nàng đối với hắn.","theLucLienQuan":["Chu Tước Tinh"],"nguon":["@c0643"]},{"id":"hau-son-thon-lac-nguyet","name":"Hậu sơn thôn Lạc Nguyệt","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Khu sau núi cạnh thôn Lạc Nguyệt, nơi an táng Tôn Thái sau khi lão qua đời.","detail":"Sau khi Tôn Thái đại nạn qua đời, mộ của lão được đặt ở sau núi cạnh thôn Lạc Nguyệt. Mộ bia do Vương Bình khắc, ghi tên Tôn Thái và thân phận nghĩa tôn của mình.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"truong-tu-thuc-trong-thon","name":"Trường tư thục trong thôn","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Trường học trong thôn Lạc Nguyệt, được dựng vào mùa xuân để trẻ nhỏ trong thôn học chữ.","detail":"Trong giai đoạn đời sống phàm tục của phụ tử Vương Lâm, thôn Lạc Nguyệt có trường tư thục được dựng lên vào mùa xuân, giúp trẻ nhỏ trong thôn có nơi học chữ.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"vu-chi-tien-gioi","name":"Vũ Chi Tiên Giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian được Tôn Thái hồi tưởng trong khoảnh khắc trước khi qua đời.","detail":"Trước lúc mất, Tôn Thái nhớ lại những chuyện mấy trăm năm trước ở Vũ Chi Tiên Giới. Địa danh này gắn với gút mắc cũ giữa lão và Vương Lâm, cũng là nguồn của lời hứa mà Vương Lâm nhắc lại khi lão lâm chung.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"lien-minh-tu-chan-dia-vuc","name":"Liên Minh Tu Chân","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực tu chân nơi Huyễn Gia Lão Tổ từng tìm kiếm hạt châu Thiên Nghịch.","detail":"Liên Minh Tu Chân được nhắc trong mạch giải thích về Huyễn Gia Lão Tổ: lão từng tìm kiếm hạt châu Thiên Nghịch tại đây, rồi tạm bỏ việc ấy để đưa Liễu Mi về Huyễn gia khi phát hiện dấu hiệu thăng hoa ý cảnh của nàng.","theLucLienQuan":["Liên Minh Tu Chân","Huyễn gia"],"nguon":["@c0645"]},{"id":"dai-vien-vuong-gia","name":"Đại viện Vương gia","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Không gian sinh hoạt của Vương Lâm và Vương Bình tại Lạc Nguyệt thôn. Đây là nơi Vương Lâm dạy con điêu khắc và đối thoại với con về việc tu đạo.","detail":"Đại viện Vương gia là nơi hai cha con Vương Lâm sống trong những năm cuối ở Lạc Nguyệt thôn. Trong sân, Vương Bình tập khắc tượng gỗ, còn Vương Lâm giảng cho con rằng điêu khắc phải dùng tâm và ký ức; cũng tại đây, Vương Lâm dứt khoát cấm Vương Bình tu đạo.","theLucLienQuan":["Vương gia"],"nguon":["@c0646"]},{"id":"nhiem-van-tinh","name":"Nhiễm Vân tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi phụ tử Vương Lâm thực hiện hành trình tám năm qua núi, sông và biển. Linh khí nơi đây đã suy giảm sau hạo kiếp nhưng vẫn được so với Chu Tước tinh năm xưa.","detail":"Nhiễm Vân tinh là không gian chính của chương, nơi Vương Lâm dẫn Vương Bình leo qua nhiều danh sơn, vượt hơn phân nửa sông ngòi rồi ra biển rộng để rèn tâm linh. Trải nghiệm thiên địa trên tinh cầu này giúp Vương Bình hoàn thành một lần thăng hoa lớn dù vẫn là phàm nhân.","theLucLienQuan":[],"nguon":["@c0647"]},{"id":"chu-tuoc-tinh","name":"Chu Tước tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu được dùng để so sánh với Nhiễm Vân tinh về mức độ linh khí. Chi tiết này nhấn mạnh Nhiễm Vân tinh dù suy giảm vẫn còn hơn Chu Tước tinh năm xưa.","detail":"Chu Tước tinh được nhắc trong phần mô tả Nhiễm Vân tinh, làm mốc so sánh về linh khí. Sự đối chiếu cho thấy bối cảnh tu luyện của Nhiễm Vân tinh sau hạo kiếp vẫn chưa hoàn toàn cằn cỗi như Chu Tước tinh trong quá khứ.","theLucLienQuan":[],"nguon":["@c0647"]},{"id":"ky-thuy-thanh","name":"Kỳ Thủy thành","cn":"","aliases":["Kỳ Thủy Thành"],"capDo":"thanh","parentId":"dai-tan-quoc-dia-diem","blurb":"Phó đô phồn hoa của Đại Tần quốc trên Nhiễm Vân tinh. Vương Lâm đưa Vương Bình vào thành và quyết định hai cha con sẽ sống tại đây.","detail":"Kỳ Thủy thành là một trong các phó đô của Đại Tần quốc, được miêu tả phồn hoa, náo nhiệt, gần sông ngòi và mức độ sầm uất gần với kinh đô. Sau khi xe ngựa tới nơi, Vương Lâm nói với Vương Bình rằng từ nay hai cha con sẽ sống ở đây và sẽ đi mua một tòa nhà.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"dai-tan-quoc-dia-diem","name":"Đại Tần quốc","cn":"","aliases":["Đại Tần"],"capDo":"quoc-gia","parentId":"nhiem-van-tinh","blurb":"Quốc gia trên Nhiễm Vân tinh, có Kỳ Thủy thành là một phó đô. Đại Tần quốc thuộc nhóm ba đại đế quốc của tinh cầu này.","detail":"Đại Tần quốc là quốc gia nơi Kỳ Thủy thành tọa lạc. Chương giới thiệu Kỳ Thủy thành là một trong các phó đô của Đại Tần quốc và đặt Đại Tần quốc trong nhóm ba đại đế quốc trên Nhiễm Vân tinh.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"tinh-nha-hien","name":"Tĩnh Nhã Hiên","cn":"","aliases":[],"capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Tửu quán hoa lệ ở thành đông Kỳ Thủy thành. Đây là nơi phụ tử Vương Lâm gặp nhóm lão nhân cẩm y, thanh niên tử y và Thanh nhi sư muội.","detail":"Tĩnh Nhã Hiên nằm ở thành đông Kỳ Thủy thành, được miêu tả là tửu quán hoa lệ. Sau khi vào thành, Vương Lâm và Vương Bình tới đây dùng bữa; xung đột nổ ra khi thanh niên tử y nhục mạ Vương Bình, lão nhân cẩm y ra tay, rồi bị Vương Lâm dùng ánh mắt trọng thương.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"thanh-bac-ky-thuy-thanh","name":"Thành bắc Kỳ Thủy Thành","cn":"","capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Khu vực phía bắc Kỳ Thủy Thành, nơi có Vương phủ của phụ tử Vương Lâm. Đoàn Tôn gia dừng lại ngoài phủ khoảng trăm trượng trước khi bái kiến.","detail":"Thành bắc Kỳ Thủy Thành là vị trí đặt Vương phủ, nơi Tôn gia tới tìm phụ tử Vương Lâm sau sự việc ở tửu lâu. Tại đây, lão nhân mặt đỏ vừa xông vào phủ đã bị lực lượng vô hình chấn thương, khiến Tôn Khải Tinh vội rút lui.","theLucLienQuan":["Tôn gia"],"nguon":["@c0651"]},{"id":"dai-dien-chi-nhanh-ton-gia-o-ky-thuy-thanh","name":"Đại điện chi nhánh Tôn gia ở Kỳ Thủy Thành","cn":"","capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Nơi Tôn Khải Tinh đưa toàn bộ tộc nhân trở về sau khi rời Vương phủ. Tại đây ông ra lệnh cấm người Tôn gia tới gần nơi ở của vị tiền bối.","detail":"Sau khi nhận ra khí tức Vấn Đỉnh trong Vương phủ, Tôn Khải Tinh lập tức đưa người Tôn gia trở về đại điện chi nhánh tại Kỳ Thủy Thành. Ông tuyên bố người nào bước vào phạm vi một ngàn trượng quanh nơi ở của tiền bối sẽ bị phế tu vi và trục xuất khỏi gia môn.","theLucLienQuan":["Tôn gia"],"nguon":["@c0651"]},{"id":"van-hai-tinh","name":"Vân Hải tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Một trong năm chủ tinh của La Thiên Bắc Vực, địa bàn của Vân gia. Vân Vô Phong xuất thân từ gia tộc này trên Vân Hải tinh.","detail":"Vân Hải tinh là nơi đặt Vân gia, đại gia tộc được gọi là đệ nhất gia tộc ở tinh cầu này. Thân phận đến từ Vân Hải tinh giúp Vân Vô Phong được các gia tộc tu chân trên Nhiễm Vân tinh nể mặt dù hắn không thể tu đạo.","theLucLienQuan":["Vân gia"],"nguon":["@c0651"]},{"id":"la-thien-bac-vuc","name":"La Thiên Bắc Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực lớn bao gồm Vân Hải tinh và Nhiễm Vân tinh. Danh tiếng Hứa Mộc từng lan rộng tại đây sau trận quét sạch Huyễn gia.","detail":"La Thiên Bắc Vực được nhắc như khu vực có năm chủ tinh, trong đó có Vân Hải tinh. Trận Hứa Mộc quét sạch Huyễn gia trên Nhiễm Vân tinh từng khiến danh tiếng của ông lưu truyền rộng trong vùng này.","theLucLienQuan":["Vân gia","Huyễn gia"],"nguon":["@c0651","@c0665"]},{"id":"bac-bo-nhiem-van-tinh","name":"Bắc bộ Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Khu vực phía bắc Nhiễm Vân tinh, nơi Thiên Hành phái xuất hiện sau ba năm Vương Bình rời Kỳ Thủy Thành. Giáo phái này nhanh chóng phát triển trong thế giới phàm nhân.","detail":"Bắc bộ Nhiễm Vân tinh trở thành nơi lưu truyền Thiên Hành phái trong phàm nhân. Tin đồn về thủ lĩnh giống tiên nhân và một nữ nhân luôn đi bên cạnh bắt đầu từ khu vực này rồi lan rộng.","theLucLienQuan":["Thiên Hành phái"],"nguon":["@c0651"]},{"id":"do-thanh-de-son-quoc","name":"Đô thành Đế Sơn quốc","cn":"","capDo":"thanh","parentId":"de-son-quoc","blurb":"Đô thành Đế Sơn quốc nằm ở bắc bộ Nhiễm Vân Tinh. Đây là nơi Vương Bình ngồi trong điện phủ xa hoa nhìn bản đồ và nhớ tới phụ thân.","detail":"Trong giai đoạn Thiên Hành phái lớn mạnh, đô thành Đế Sơn quốc là trung tâm thế tục nơi Vương Bình xử lý cục diện trước khi Đế Sơn quốc bị thay thế. Cảnh đêm tại điện phủ cho thấy Vương Bình đã rời xa sơn thôn tuổi trẻ và đứng giữa vòng xoáy quyền lực.","theLucLienQuan":["Đế Sơn quốc","Thiên Hành phái","Thiên Hành đế quốc"],"nguon":["@c0652"]},{"id":"ky-lien-son","name":"Kỳ Liên Sơn","cn":"","capDo":"vuc","parentId":"nhiem-van-tinh","blurb":"Kỳ Liên Sơn là dãy núi Vương Bình nhìn về từ doanh trướng khi đã trở thành chí tôn phàm nhân. Nơi này gợi lại sơn thôn và thời thơ ấu của hắn.","detail":"Khi chiến sự đang diễn ra, Vương Bình ra ngoài doanh trướng nhìn về hướng Kỳ Liên Sơn. Thanh Nghi nhắc đó là nơi gắn với thời thơ ấu của hắn, làm nổi bật nỗi mệt mỏi của Vương Bình trước quyền lực thế tục.","theLucLienQuan":["Thiên Hành đế quốc"],"nguon":["@c0652"]},{"id":"thon-nho-trong-nui","name":"Thôn nhỏ trong núi","cn":"","aliases":[],"capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Thôn nhỏ trên Nhiễm Vân tinh nơi Vương Bình và Thanh Nghi cư trú trong biến cố Lôi Đạo Tử.","detail":"Đây là nơi thần thức Lôi Đạo Tử tập trung sau khi hắn bao trùm toàn bộ Nhiễm Vân tinh. Vương Bình và Thanh Nghi đối diện Lôi Đạo Tử tại căn phòng trong thôn, trước khi lôi quang của hắn phá tan căn phòng và đẩy hai người vào nguy hiểm trực tiếp.","theLucLienQuan":[],"nguon":["@c0655"]},{"id":"thon-tren-nhiem-van-tinh","name":"Thôn trên Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Ngôi thôn nơi Lôi Đạo Tử tấn công Vương Bình trước khi Vương Lâm hiện thân cứu con.","detail":"Tại thôn này, Vương Bình đối diện lôi quang của Lôi Đạo Tử và được Vương Lâm dùng Định cứu kịp thời. Thôn dân không xuất hiện trong cuộc đối đầu vì trước đó đã bị thần thức quét qua làm bất tỉnh.","theLucLienQuan":[],"nguon":["@c0656"]},{"id":"binh-nguyen-phia-tay-nhiem-van-tinh","name":"Bình nguyên phía tây Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Chiến trường Vương Lâm chọn sau khi đưa Vương Bình và Thanh Nghi rời khỏi thôn.","detail":"Vương Lâm dùng ánh sáng dịu dàng bao lấy Vương Bình và Thanh Nghi rồi đưa họ tới bình nguyên phía tây Nhiễm Vân tinh để tránh liên lụy thôn dân. Lôi Đạo Tử đuổi tới, xuất hiện cách đó năm trăm trượng và giao chiến với Vương Lâm tại đây.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0656"]},{"id":"tinh-cau-mau-xam-hoang-phe","name":"Tinh cầu màu xám hoang phế","cn":"","capDo":"tinh-cau","parentId":"tinh-khong","blurb":"Tinh cầu hoang không có linh lực, nơi Vương Lâm đưa Lôi Đạo Tử tới để tiếp tục xử lý.","detail":"Tinh cầu này có đất xám, gió bão và khí độc, không có linh lực. Vương Lâm chọn nơi đây để mở động phủ tạm, hạ cấm chế và bắt đầu luyện Lôi Đạo Tử thành tiên vệ.","theLucLienQuan":[],"nguon":["@c0660"]},{"id":"dong-phu-moi-tren-tinh-cau-mau-xam","name":"Động phủ mới trên tinh cầu màu xám","cn":"","capDo":"khac","parentId":"tinh-cau-mau-xam-hoang-phe","blurb":"Động phủ tạm do Vương Lâm dùng kiếm khí khoét ra trên tinh cầu xám.","detail":"Động phủ gồm bốn phòng một đại sảnh, được Vương Lâm dùng kiếm khí đẽo gọt mà thành. Đây là nơi hắn khiến Lôi Đạo Tử tưởng chỉ chịu cấm chế thứ hai, rồi thật sự bắt đầu luyện chế đối phương thành tiên vệ.","theLucLienQuan":[],"nguon":["@c0660"]},{"id":"dong-phu-tren-tinh-cau-bo-hoang","name":"Động phủ","cn":"","capDo":"khac","parentId":"tinh-cau-mau-xam-hoang-phe","blurb":"Động phủ trên tinh cầu bỏ hoang, nơi Vương Lâm khống chế nguyên thần và tế luyện thân thể Lôi Đạo Tử.","detail":"Trong động phủ này, Vương Lâm bố trí tiên vệ khôi lỗi, lôi thú, ba chung cực chủ hồn, Thất Tinh kiếm trận và cấm chế điện quang để áp chế nguyên thần Lôi Đạo Tử, đồng thời tiến hành tế luyện thân thể hắn thành tiên vệ khôi lỗi.","theLucLienQuan":[],"nguon":["@c0661"]},{"id":"tieu-tinh-cau-hoang-da-thuoc-pham-vi-huyet-to","name":"Tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ, không có sinh linh và đang chết dần. Đây là nơi Tử Tâm điều tra trước khi tinh cầu tan vỡ để lộ bản tôn Vương Lâm.","detail":"Tinh cầu này có mặt đất khô nứt, núi sụp, sông cạn và biến đổi kỳ dị trong nhiều năm, giống như đã sống ngắn ngủi rồi đi tới tận cùng. Khi Tử Tâm dùng thần thức dò vào sâu, nàng bị uy áp bên trong đẩy lui; sau đó tinh cầu sụp đổ, sóng gợn bùng phát và bản tôn Vương Lâm hiện ra từ trung tâm.","theLucLienQuan":["Huyết Tổ thế lực"],"nguon":["@c0663"]},{"id":"tinh-cau-hoang-da-co-tang-loi-quang","name":"Tinh cầu hoang dã có tầng lôi quang","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tinh cầu hoang dã có tầng lôi quang tự nhiên bao phủ. Bản tôn Vương Lâm chọn nơi này để dung nhập vào lòng tinh cầu và tiếp tục tu luyện.","detail":"Vài tháng sau khi rời tinh cầu đã tan vỡ, bản tôn Vương Lâm chọn một tinh cầu hoang dã có tầng lôi quang tự nhiên. Hắn nhìn trúng đặc điểm này, dung nhập vào lòng tinh cầu rồi khoanh chân nhắm mắt tiếp tục tu luyện.","theLucLienQuan":[],"nguon":["@c0663"]},{"id":"huyet-hai-co-than-chi-dia","name":"Huyết Hải","cn":"","capDo":"khac","parentId":"co-than-chi-dia","blurb":"Huyết Hải nằm bên trong Cổ Thần Chi Địa. Đây là nơi nhiều tu sĩ khoanh chân hấp thu lực lượng, còn Thác Sâm ngồi trên cột đá lớn nhất.","detail":"Trong Huyết Hải của Cổ Thần Chi Địa, nhiều tu sĩ khoanh chân tu luyện và tu vi tăng mạnh. Ở cột đá lớn nhất, Thác Sâm khắc đầy tên Vương Lâm, bên cạnh có thiết kiếm rỉ sét và tuyên bố sắp thoát khỏi nơi này.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0663"]},{"id":"dinh-chu-tuoc-son","name":"Đỉnh Chu Tước Sơn","cn":"","capDo":"khac","parentId":"chu-tuoc-son","blurb":"Đỉnh Chu Tước Sơn là nơi Chu Như mở túi trữ vật Vương Lâm lưu lại. Tại đây, ký ức bị phong ấn của nàng được bạch quang giải khai.","detail":"Trên đỉnh Chu Tước Sơn, Chu Như đã trưởng thành hơn và cầm túi trữ vật cũ của Vương Lâm. Khi nàng mở túi, bạch quang nhập vào mi tâm, ký ức bị phong ấn chậm rãi cởi bỏ, khiến nàng khóc bên Tiểu Bạch.","theLucLienQuan":["Chu Tước Tinh"],"nguon":["@c0663"]},{"id":"vong-nguyet","name":"Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Ký sinh thể của Cổ Thần trên Vân Hà tinh được Vương Lâm nghĩ tới khi tìm Cổ Thần Khí.","detail":"Vương Lâm cho rằng Vọng Nguyệt thân là ký sinh thể của Cổ Thần, có thể còn liên quan tới Cổ Thần Khí còn sót lại. Vì bản tôn cần Cổ Thần Khí để trưởng thành, hắn dự định sau này nên tới Vân Hà tinh thăm dò.","theLucLienQuan":["Cổ Tộc"],"nguon":["@c0664"]},{"id":"loi-chi-tien-gioi","name":"Lôi Chi tiên giới","cn":"","capDo":"gioi-nho","parentId":"la-thien-tinh-vuc","blurb":"Nơi sẽ mở ra sau trăm năm và gắn với cơ hội của Huyễn Gia.","detail":"Huyễn Phong Thần nói Huyễn Gia giao toàn bộ Thăng Tiên quả cho Vương Lâm đồng nghĩa buông bỏ cơ hội tiến vào Lôi Chi tiên giới sau trăm năm.","theLucLienQuan":["Huyễn Gia","Lôi Tiên Điện"],"nguon":["@c0664","@c0725"]},{"id":"thien-gia-thanh","name":"Thiên gia thành","cn":"","capDo":"thanh","parentId":"thien-huyen-tinh","blurb":"Thành trì của Thiên gia trên Thiên Huyễn Tinh.","detail":"Nơi Thiên Quỳ Tử cùng một ngàn tu sĩ Thiên gia ra ngoài cung kính nghênh đón Vương Lâm trong thân phận Sứ giả Lôi Tiên Điện.","theLucLienQuan":["Thiên gia"],"nguon":["@c0665"]},{"id":"van-ha-tinh","name":"Vân Hà Tinh","aliases":["Vọng Nguyệt"],"cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Tinh cầu thực chất là thân thể của Vọng Nguyệt, hiện bị sương mù và xúc tu bao phủ.","detail":"Vương Lâm tới đây để tìm Kim Viêm quáng mạch trong xương Vọng Nguyệt; mặt đất đầy xúc tu đỏ sậm, bên trong có niêm dịch, tiên lực bất thường và nơi bài tiết hấp thu.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"suong-mu-van-ha-tinh","name":"Sương mù Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Lớp sương mù dày đặc quanh Vân Hà Tinh, cản thần thức và ẩn xúc tu tập kích.","detail":"Vương Lâm dùng Lôi Thú và Thất Tinh kiếm trận mở đường rất chậm, nhưng khi gần ra khỏi sương mù vẫn bị xúc tu tập kích và mất kiếm trận.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"long-dat-van-ha-tinh","name":"Lòng đất Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Không gian niêm dịch trong thân thể Vọng Nguyệt, nơi chứa xương và Kim Viêm quáng mạch.","detail":"Vương Lâm đi sâu vào đây, phát hiện dao động tiên lực bất thường và tạm dừng hấp thu xương để tìm nguy cơ tiềm ẩn.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"hang-dong-ben-trong-van-ha-tinh","name":"Hang động rộng bên trong Vân Hà Tinh","cn":"","capDo":"khac","parentId":"long-dat-van-ha-tinh","blurb":"Hang động nơi Tham Lang bị mắc kẹt trong đại đỉnh.","detail":"Vị trí này nằm trong nơi bài tiết của Vọng Nguyệt, có hồng vụ, chất bẩn tanh tưởi và điện quang phun ra từ vách động.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"noi-hap-thu-bai-tiet-vong-nguyet","name":"Nơi hấp thu bài tiết của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"long-dat-van-ha-tinh","blurb":"Khu vực bài tiết và hấp thu lại vật chất trong thân thể Vọng Nguyệt.","detail":"Tham Lang bị kẹt tại đây trong đại đỉnh; nơi này phun ra hồng vụ, vật dơ bẩn và điện quang sau khi xúc tu bị kích thích.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"xuong-cua-vong-nguyet","name":"Xương của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Bộ xương bên trong thân thể Vọng Nguyệt, nơi Vương Lâm phát hiện khe lớn và sơn thạch mắc kẹt.","detail":"Khe trên xương gần như chặt đứt bộ xương, có niêm dịch khô, Kim Viêm thạch và sơn thạch của Tham Lang đã bị đồng hóa.","theLucLienQuan":[],"nguon":["@c0667"]},{"id":"bun-dat-trong-than-the-vong-nguyet","name":"Bùn đất trong thân thể Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Môi trường bùn đất trong thân thể Vọng Nguyệt, nơi con Vọng Nguyệt nhỏ ẩn nấp.","detail":"Vương Lâm dùng thần thông chạy trốn xuyên vào bùn đất sau khi đoạt sơn thạch và bị phục kích.","theLucLienQuan":[],"nguon":["@c0667"]},{"id":"cho-bi-son-thach-tap-tru","name":"Chỗ bị sơn thạch tạp trụ","cn":"","capDo":"khac","parentId":"xuong-cua-vong-nguyet","blurb":"Vị trí xương Vọng Nguyệt từng bị sơn thạch của Tham Lang kẹt vào.","detail":"Vương Lâm quay lại nơi này sau khi rời khu bài tiết, quan sát an toàn rồi ngồi xuống kích hoạt lạc ấn Thăng Tiên quả và thi triển Hoàng Tuyền lực.","theLucLienQuan":[],"nguon":["@c0668"]},{"id":"trieu-tich-tham-uyen","name":"Triều tịch thâm uyên","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Nơi gắn với cảm ngộ Hoàng Tuyền lực của Vương Lâm.","detail":"Được nhắc như nguồn cảm ngộ đệ tam thức, liên hệ lực lượng thiên địa vô hình sinh ra khi hai tinh vực giao thoa.","theLucLienQuan":[],"nguon":["@c0668"]},{"id":"tinh-khong-vo-tan","name":"Tinh không vô tận","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Khoảng không bên ngoài Vân Hà Tinh, là đích thoát thân của Vương Lâm và Tiên Vệ sau khi xuyên qua tầng sương mù. Trong chương 670, nó được mở lộ khi sương mù lâu năm tiêu tán.","detail":"Sau khi Cấm Phiên và Thất Tinh Kiếm Trận bị hy sinh để tranh thủ từng khoảnh khắc, Vương Lâm cùng Tiên Vệ lao qua tầng sương mù hướng tới bầu trời bên ngoài. Khi sương mù Vân Hà Tinh tiêu tán, tinh không vô tận trở thành con đường sống trước cuộc truy đuổi của Vọng Nguyệt.","theLucLienQuan":[],"nguon":["@c0670"]},{"id":"co-the-vong-nguyet","name":"Cơ thể Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Không gian địa thể thực chất của Vân Hà Tinh, nơi mặt đất là thân thể Vọng Nguyệt.","detail":"Khi Vọng Nguyệt thức tỉnh, khe nứt khổng lồ mở ra như miệng lớn, bên trong có Thất Tinh Kiếm Trận tự bạo và khu vực bài tiết, hấp thu nơi Tham Lang tìm được đường thoát. Sự xoay mình của cơ thể này khiến lục địa bám trên thân Vọng Nguyệt vỡ vụn và sương mù lâu năm tiêu tán.","theLucLienQuan":[],"nguon":["@c0671"]},{"id":"tinh-khong-quanh-van-ha-tinh","name":"Tinh không quanh Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Vùng tinh không nơi Vương Lâm bỏ chạy và Vọng Nguyệt triển khai truy sát.","detail":"Sau khi lao khỏi Vân Hà Tinh, Vương Lâm dùng Tinh La Bàn mang xương Vọng Nguyệt chạy trong tinh không quanh đó. Đây cũng là nơi đàn Vọng Nguyệt nhỏ xuất hiện, Tham Lang dùng cự đỉnh và bình phong Sơn Hà Đồ, còn một chỉ Cổ Thần được huyễn hóa.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0672"]},{"id":"khe-nut-mieng-vong-nguyet","name":"Khe nứt miệng Vọng Nguyệt","cn":"","capDo":"khac","parentId":"co-the-vong-nguyet","blurb":"Lối mở trong cơ thể Vọng Nguyệt mà Tham Lang nhiều lần cố lao qua để thoát thân.","detail":"Khe nứt mở ra khi Vọng Nguyệt nuốt nửa xương, trở thành cơ hội thoát thân của Tham Lang. Tuy nhiên khe nứt nhiều lần khép lại hoặc bị biến cố cản trở, khiến hắn tiếp tục rơi vào hiểm cảnh.","theLucLienQuan":[],"nguon":["@c0672"]},{"id":"tinh-khong-noi-vong-nguyet-thuc-tinh","name":"Tinh không nơi Vọng Nguyệt thức tỉnh","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Chiến trường chính của chương, nơi Vương Lâm, Tham Lang và Vọng Nguyệt giao phong sau khi cự thú thức tỉnh.","detail":"Khu vực tinh không này là nơi bình phong Sơn Hà Đồ trôi nổi, Tham Lang dùng Tôn Tiên Đế Quan chống Cổ Thần Chỉ, Vương Lâm bị phá hủy nhục thân rồi nguyên thần hóa thái cổ Lôi Long bỏ chạy. Vọng Nguyệt tiếp tục truy đuổi từ đây sau khi Cổ Thần Chỉ tiêu tán.","theLucLienQuan":[],"nguon":["@c0673"]},{"id":"phuong-xa-trong-tinh-khong","name":"Phương xa trong tinh không","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Vị trí vương miện của Tham Lang trôi nổi sau khi hắn bị Cổ Thần Chỉ đánh bay.","detail":"Trong lúc nguyên thần Vương Lâm bỏ chạy, hắn phát hiện Tôn Tiên Đế Quan trôi ở phương xa trong tinh không, dùng thần thức thu lấy rồi tiếp tục đào thoát không quay đầu.","theLucLienQuan":[],"nguon":["@c0673"]},{"id":"la-thien-nam-vuc","name":"La Thiên Nam Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Một đại vực của La Thiên, nằm đối ứng với La Thiên Bắc Vực; Vương Lâm chạy sang đây sau khi thoát khỏi Vọng Nguyệt.","detail":"La Thiên Nam Vực là khu vực Vương Lâm tiến vào trong cuộc đào thoát khỏi Vọng Nguyệt. Khi đến ranh giới giữa Nam Vực và Bắc Vực, Vọng Nguyệt dừng lại không dám vượt qua, khiến Vương Lâm nghi ngờ nơi này tồn tại điều gì đó làm dị thú kiêng kỵ. Trong Nam Vực, hắn cảm ứng được khu vực tầng đá che giấu một tiểu tinh cầu lôi điện thích hợp để chữa thương và tái tạo thân thể.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"ranh-gioi-la-thien-nam-bac-vuc","name":"Ranh giới La Thiên Nam-Bắc Vực","cn":"","capDo":"khac","parentId":null,"blurb":"Đường phân cách giữa La Thiên Bắc Vực và La Thiên Nam Vực, nơi Vọng Nguyệt dừng truy sát Vương Lâm.","detail":"Ranh giới La Thiên Nam-Bắc Vực là điểm mấu chốt trong cuộc truy đuổi của Vọng Nguyệt. Vương Lâm vượt qua khu vực này sang Nam Vực, còn Vọng Nguyệt vì ký ức cảnh cáo mơ hồ và cảm giác khủng hoảng nên không dám tiếp tục, từ đó giúp Vương Lâm thoát khỏi tử cục.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tinh-cau-loi-quang-loi-nguc","name":"Tinh cầu lôi quang / Lôi Ngục","cn":"","capDo":"tinh-cau","parentId":"la-thien-nam-vuc","blurb":"Tiểu tinh cầu bỏ hoang trong La Thiên Nam Vực, bị tầng đá che phủ và tràn đầy lôi điện tiên thiên.","detail":"Tinh cầu lôi quang, còn được gọi là Lôi Ngục, là một tiểu tinh cầu bỏ hoang ẩn sau tầng đá dày đặc ở La Thiên Nam Vực. Nơi này không có sinh linh, không có linh khí, nhưng sinh cơ nồng đậm và tràn ngập lôi quang tự nhiên do trời đất sinh ra. Vương Lâm chọn nơi đây làm động phủ tạm thời, dùng lôi lực để khôi phục nguyên thần trong mười năm, rồi mượn Cổ Thần Quyết và lôi điện toàn tinh cầu để bắt đầu ngưng tụ lại thân thể.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tang-da-bao-quanh-tinh-cau-loi-quang","name":"Tầng đá bao quanh tinh cầu lôi quang","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Lớp đá dày đặc che giấu tiểu tinh cầu lôi quang bên trong La Thiên Nam Vực.","detail":"Tầng đá bao quanh tinh cầu lôi quang dày đặc như một bức tường thiên nhiên, khiến thần thức khó dò xét sâu vào bên trong. Vương Lâm để Tiên Vệ xuyên qua trước, nhờ đó phát hiện tiểu tinh cầu bỏ hoang tràn đầy lôi điện ở phía trong. Về sau hắn còn cảm thấy nơi khiến mình dễ chịu hơn có thể nằm sâu hơn trong tầng đá này.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tinh-cau-nguyen-thuy-la-thien-bac-vuc","name":"Tinh cầu nguyên thủy ở La Thiên Bắc Vực","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Một tinh cầu nguyên thủy trong La Thiên Bắc Vực, nơi Tham Lang rơi xuống và ẩn vào lòng đất.","detail":"Tinh cầu nguyên thủy ở La Thiên Bắc Vực có linh khí không đậm nhưng có phàm nhân cư trú. Tham Lang rơi xuống vùng đồng bằng phía bắc của tinh cầu này trong tình trạng thân thể vỡ nát, nguyên thần hao tổn nặng, sau đó chìm xuống lòng đất để chờ ngày khôi phục. Từ đó phàm nhân trên tinh cầu thường ngửi thấy mùi tanh mơ hồ như phát ra từ dưới đất.","theLucLienQuan":["Phàm nhân trên tinh cầu nguyên thủy"],"nguon":["@c0674"]},{"id":"loi-tri-tren-tinh-cau-loi-quang","name":"Lôi Trì trên tinh cầu lôi quang","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Khu vực mặt đất trên tinh cầu lôi quang hấp thu và phóng thích lôi điện như ao sấm.","detail":"Lôi Trì trên tinh cầu lôi quang là nơi lôi điện tụ tập dày đặc trên mặt đất, liên tục hấp thu và phóng thích lôi lực. Vương Lâm ngồi trong lôi quang để khôi phục nguyên thần, rồi dẫn lôi lực từ Lôi Trì nhập vào nguyên thần, ngưng tụ xương tay, xương ngón và dần hình thành khung xương mới.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"day-nui-do-xuong-mat-trang-hoa-thanh","name":"Dãy núi do xương mặt trăng hóa thành","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Dãy núi giống Thần Long nằm sấp trên tinh cầu lôi quang, do xương mặt trăng hóa thành. Bên trong chứa Kim Viên Quáng để Thiên Nghịch hấp thu.","detail":"Vương Lâm đặt Thiên Nghịch Châu lên dãy núi này để hấp thu thuộc tính kim. Kim Viên Quáng trong xương hóa thành tơ vàng bị hạt châu hút dần, sau ba tháng bị hấp thu hết, chỉ còn lại một tòa núi đá.","theLucLienQuan":[],"nguon":["@c0675"]},{"id":"vung-dat-yeu-linh","name":"Vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng đất được nhắc lại trong hồi tưởng của Vương Lâm về lần đối mặt Thiên Kiếp khi tiến lên Vấn Đỉnh.","detail":"Trong lúc đứng trước cánh cửa tím của Thiên Nghịch, Vương Lâm nhớ lại cảm giác khi từng đối mặt Thiên Kiếp ở vùng đất Yêu Linh để so sánh với nỗi sợ bản năng hiện tại.","theLucLienQuan":[],"nguon":["@c0676"]},{"id":"nui-hang-nhac-phai","name":"Núi Hằng Nhạc Phái","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm trong hồi ức thời thiếu niên của Vương Lâm. Nơi này gắn với cảm giác kính sợ ban đầu của hắn trước môn phái tu tiên.","detail":"Khi nhìn cánh cửa tím khổng lồ, Vương Lâm nhớ lại thời còn là thiếu niên phàm nhân, đứng trên núi nhìn Hằng Nhạc Phái nguy nga và vẫn kiên định leo lên dù toàn thân đổ máu.","theLucLienQuan":["Hằng Nhạc Phái"],"nguon":["@c0676"]},{"id":"canh-cua-mau-tim","name":"Cánh cửa màu tím","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Dị tượng khổng lồ xuất hiện sau khi Thiên Nghịch ngũ hành viên mãn. Cánh cửa đứng giữa thiên địa và có cánh tay tử quang vẫy gọi Vương Lâm.","detail":"Sau khi Hạt Châu Thiên Nghịch phóng xuất hơn phân nửa lực ngũ hành tích lũy, một cánh cửa màu tím hiện ra giữa thiên địa. Nó không phát uy áp rõ rệt nhưng khiến Vương Lâm sinh nỗi sợ từ linh hồn; bên ngoài cửa, tử quang ngưng tụ thành cánh tay khổng lồ, vừa vẫy gọi vừa có thể nhẹ nhàng phá hủy xương Vọng Nguyệt và xé nát không gian quanh tinh cầu.","theLucLienQuan":[],"nguon":["@c0676"]},{"id":"canh-cua-thien-dia","name":"Cánh cửa thiên địa","cn":"","capDo":"khac","parentId":null,"blurb":"Cánh cửa khổng lồ xuất hiện cùng cánh tay bí ẩn trong biến cố Thiên Nghịch. Nó tan biến sau khi cánh tay vẫy gọi Vương Lâm.","detail":"Cánh cửa thiên địa là nơi cánh tay khổng lồ vươn ra, thể hiện loại quy tắc khiến Vương Lâm kinh sợ. Sau khi cánh tay cùng cánh cửa biến mất, tử quang co lại thành Thiên Nghịch Châu, để lại nghi vấn về nơi cánh cửa thông tới và các chủ nhân Thiên Nghịch trước kia.","theLucLienQuan":[],"nguon":["@c0677"]},{"id":"tien-vuc-vien-co","name":"Tiên vực viễn cổ","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Không gian được Vương Lâm nêu như giả thuyết về đích đến của cánh cửa thiên địa. Chương này chưa xác nhận cánh cửa thật sự thông tới nơi đó.","detail":"Khi suy đoán về lai lịch Thiên Nghịch và cánh cửa sau khi ngũ hành viên mãn, Vương Lâm nghĩ tới khả năng cánh cửa liên quan đến tiên vực viễn cổ. Đây chỉ là nghi vấn trong dòng suy luận của hắn, chưa có kết luận chắc chắn.","theLucLienQuan":["Tiên Vực thời viễn cổ"],"nguon":["@c0677"]},{"id":"tang-da-vun-nam-vuc-la-thien","name":"Tầng đá vụn Nam Vực La Thiên","cn":"","capDo":"khac","parentId":"la-thien-nam-vuc","blurb":"Khu vực tầng đá vụn ở Nam Vực La Thiên, gắn với truyền thuyết nơi Thiên Nghịch lần đầu xuất hiện.","detail":"Nơi này được đồn là địa phương hạt châu Thiên Nghịch thần bí lần đầu hiện thế năm xưa. Sự xuất hiện ấy gây ra dị biến Lôi Đình, khiến khu vực dần trở thành Lôi Ngục thích hợp cho tu sĩ tu luyện thần thông Lôi hệ và hấp thụ nguyên lực.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0678"]},{"id":"khong-gian-thien-nghich","name":"Không gian Thiên Nghịch","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian hỗn độn vô biên bên trong cánh cửa Thiên Địa do Thiên Nghịch mở ra. Đây là nơi Vương Lâm chứng kiến vật sáng sinh diệt thành tinh cầu và bước vào trạng thái truy tìm Đạo.","detail":"Sau khi tâm thần bị hút qua khe cửa, Vương Lâm nhận ra nơi này là không gian Thiên Nghịch. Trong không gian ấy, những vật sáng bành trướng thành tinh cầu có đại lục, sông biển, linh khí rồi lại thoái hóa về vật sáng, khiến hắn chìm sâu vào cảm ngộ sinh diệt và truy tìm dấu chân của Đạo.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"tinh-cau-do-vat-sang-hoa-thanh","name":"Tinh cầu do vật sáng hóa thành","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Các vật sáng trong không gian Thiên Nghịch bành trướng thành tinh cầu rồi lại thoái hóa. Chúng là cảnh tượng then chốt khiến Vương Lâm quan sát sinh diệt và lần theo lực lượng thần bí phía sau.","detail":"Những vật sáng trong không gian Thiên Nghịch hóa thành tinh cầu có đại lục, sông biển và linh khí nồng đậm, sau đó biến đổi ngược về vật sáng như thời gian đảo chiều. Quá trình lặp lại này khiến tâm thần Vương Lâm dần chìm vào trạng thái quên hết mọi sự.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"ba-tinh-cau-am-ap","name":"Ba tinh cầu ấm áp","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Một tinh cầu tự nhiên có sức sống yếu nhưng ấm áp, kèm hai tinh cầu nhỏ bên cạnh mang khí tức quyến luyến. Sau khi Vương Lâm chạm vào hư vô, cả ba hóa thành hào quang nhập vào đầu hắn.","detail":"Ba tinh cầu này khác với những vật sáng sinh diệt thông thường trong không gian Thiên Nghịch: một tinh cầu có hơi ấm yếu ớt, hai tinh cầu nhỏ ở gần tỏa cảm giác quyến luyến. Khi Vương Lâm chạm nhẹ hư vô, chúng tiêu tan thành ba đạo hào quang dung nhập vào đầu hắn, khiến hắn dừng việc truy tìm và bước sang trạng thái hóa thành vật sáng.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"tinh-cau-sau-khi-vuong-lam-hoa-thanh-vat-sang","name":"Tinh cầu sau khi Vương Lâm hóa thành vật sáng","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Tinh cầu do chính trạng thái vô thức của Vương Lâm hóa thành sau khi ba luồng hào quang nhập vào đầu hắn. Nơi này có núi sông, biển cả, thôn trang phàm nhân, một hộ gia đình phía bắc và cô gái áo trắng phía nam.","detail":"Sau khi Vương Lâm hóa thành vật sáng và hấp thu bụi bặm xung quanh, một tinh cầu dần hình thành với núi non, sông suối, biển cả và đời sống phàm tục. Trên tinh cầu ấy, một nam một nữ sống ở phía bắc, cô gái áo trắng xuất hiện phía nam; qua vô số năm tháng, ba người này là điều duy nhất không biến mất.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"vu-tien-gioi","name":"Vũ Tiên Giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Vũ Tiên Giới là tiên giới Vương Lâm từng vào trước đây, được hắn đem so sánh với Lôi Tiên Giới. Khi ở Vũ Tiên Giới, hắn chưa thể hấp thụ tiên ngọc như hiện tại.","detail":"Trong lúc nghe tin Lôi Tiên Giới sắp mở, Vương Lâm nhớ tới lần từng vào Vũ Tiên Giới. Sự khác biệt là khi đó hắn chưa đủ khả năng hấp thụ tiên ngọc, còn hiện tại Lôi Tiên Giới có thể trở thành cơ hội giúp tu vi viên mãn.","theLucLienQuan":["Tứ đại tiên giới Phong, Vũ, Lôi, Điện"],"nguon":["@c0681","@c0696","@c0746"]},{"id":"trung-tam-loi-tri","name":"Trung tâm Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tri-tren-tinh-cau-loi-quang","blurb":"Trung tâm Lôi Trì là khu vực Vương Lâm hướng tới sau hai năm tu luyện vì lôi đình nơi đó mạnh hơn nhiều so với vùng ngoài.","detail":"Vương Lâm nhận ra càng gần trung tâm Lôi Trì thì lôi đình càng mạnh và nguyên lực ẩn chứa càng nhiều; một đạo lôi đình gần trung tâm được nhận định vượt xa trăm đạo ở ngoài rìa, nên hắn quyết định tiến sâu hơn để tăng tốc khôi phục nguyên lực.","theLucLienQuan":[],"nguon":["@c0682"]},{"id":"thien-dia-dai-mon","name":"Thiên Địa Đại Môn","cn":"","capDo":"khac","parentId":null,"blurb":"Mốc không gian được nhắc lại trong liên tưởng của Vương Lâm khi cảm ngộ Lôi Trì.","detail":"Vương Lâm từng ở ngoài Thiên Địa Đại Môn và nhìn qua khe hở vào không gian Nghịch Thiên. Trải nghiệm đó được dùng để so sánh với trạng thái quên thân, chỉ còn quan sát bản chất kỳ dị của Lôi Trì.","theLucLienQuan":[],"nguon":["@c0683"]},{"id":"loi-tri","name":"Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Không gian lôi đình nơi Vương Lâm tu luyện và nơi Thân Công Hổ đối đầu Chiến Không Liệt.","detail":"Lôi Trì có lôi đình dày đặc, càng vào vòng trong thì thiên địa nguyên lực càng khổng lồ. Chương này diễn ra tại khu vực Lôi Trì, khi Vương Lâm thổ nạp lôi đình còn Thân Công Hổ và Chiến Không Liệt chuẩn bị giao chiến bên ngoài phạm vi hắn đang ngồi.","theLucLienQuan":["Lôi Tiên Điện","Gia tộc Thân Công","Chiến gia"],"nguon":["@c0684"]},{"id":"vong-trong-loi-tri","name":"Vòng trong Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tri","blurb":"Khu vực sâu trong Lôi Trì nơi Vương Lâm tỉnh lại và tiếp tục thổ nạp lôi đình.","detail":"Vòng trong Lôi Trì có lôi đình nồng đậm hơn ngoài rìa rất nhiều. Vương Lâm tỉnh lại tại đây, vẫn còn cách trung tâm rất xa, nhưng vị trí ấy đã vượt quá khả năng tiến vào của Chiến Không Liệt với tu vi Dương Thực viên mãn, khiến hắn sinh nghi.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0684"]},{"id":"noi-hoang-da-o-la-thien-tinh-vuc","name":"Nơi hoang dã ở La Thiên Tinh Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực Vương Lâm chọn tìm đến sau khi rời Lôi Trì. Nơi này phần lớn là tinh cầu bỏ hoang, ít tu sĩ qua lại, nhưng vẫn có một số tinh cầu có phàm nhân và gia tộc tu chân bậc thấp.","detail":"Theo tinh đồ trong ngọc giản của Thân Công Hổ, Vương Lâm chọn vùng hoang dã ở La Thiên Tinh Vực để tìm nơi bí mật tu luyện. Khu vực này ít bị tu sĩ chú ý, phù hợp với mục tiêu tăng tu vi, chỉnh lý thần thông và chuẩn bị cho Lôi Tiên Giới.","theLucLienQuan":[],"nguon":["@c0686"]},{"id":"tinh-cau-bo-hoang-giong-chu-tuoc-tinh","name":"Tinh cầu bỏ hoang giống Chu Tước Tinh","cn":"","capDo":"tinh-cau","parentId":"noi-hoang-da-o-la-thien-tinh-vuc","blurb":"Tinh cầu có sự sống khiến Vương Lâm nhớ tới Chu Tước Tinh vì cảm giác và hơi thở tương tự. Đây là nơi hắn chọn tiến vào sau khi rời Lôi Trì.","detail":"Tinh cầu này nằm trong vùng hoang dã của La Thiên Tinh Vực, có phàm nhân sinh sống và tu sĩ cấp thấp. Cảm giác giống Chu Tước Tinh khiến Vương Lâm nhớ quê cũ, từ đó quyết định đi vào và cuối cùng chọn Thanh Linh Tinh, Hoành Vân Phong làm điểm dừng chân.","theLucLienQuan":["Trương gia"],"nguon":["@c0686"]},{"id":"thanh-linh-tinh","name":"Thanh Linh Tinh","cn":"","capDo":"tinh-cau","parentId":"noi-hoang-da-o-la-thien-tinh-vuc","blurb":"Tinh cầu màu xanh nước biển, biển chiếm hơn phân nửa và sức sống dày đặc. Trên tinh cầu có nhiều quốc gia phàm nhân, gia tộc tu chân, nhưng tu sĩ cao nhất chỉ đến Nguyên Anh.","detail":"Thanh Linh Tinh là nơi Vương Lâm đặt chân sau khi rời Lôi Trì và tìm một tu chân tinh thuộc về mình tại La Thiên Tinh Vực. Tinh cầu này gợi cảm giác giống Chu Tước Tinh, có sinh cơ mạnh, nhiều phàm nhân và thế lực tu chân cấp thấp, trong đó Trương gia là gia tộc nổi bật.","theLucLienQuan":["Trương gia"],"nguon":["@c0686","@c0698"]},{"id":"hoanh-van-phong","name":"Hoành Vân Phong","cn":"","aliases":["Hoành Vân Sơn Phong"],"capDo":"khac","parentId":"thanh-linh-tinh","blurb":"Ngọn núi cao nhất trên Thanh Linh Tinh, thuộc địa bàn Trương gia. Đây là nơi tộc nhân Nguyên Anh đại viên mãn của Trương gia thường lên bế quan tọa hóa trước khi hết thọ nguyên.","detail":"Hoành Vân Phong có linh khí loãng nhưng địa thế hùng vĩ, là biểu tượng trọng yếu trên Thanh Linh Tinh. Vương Lâm chọn nơi này làm điểm dừng chân; cùng lúc đó, Trương Tân Hải lên đỉnh núi chuẩn bị tọa hóa và kinh sợ khi thấy Vương Lâm đứng trên thạch đài mà thần thức không phát hiện được.","theLucLienQuan":["Trương gia"],"nguon":["@c0686"]},{"id":"vung-quanh-ngon-nui-hoanh-van-phong","name":"Vùng quanh ngọn núi trong phạm vi ngàn dặm vạn dặm","cn":"","capDo":"khac","parentId":"hoanh-van-phong","blurb":"Khu vực quanh Hoành Vân Phong nơi Vương Lâm cho Hứa Lập Quốc hoạt động có giới hạn.","detail":"Vương Lâm cho Hứa Lập Quốc tạm thời không phải quay lại túi trữ vật, được hoạt động và lĩnh ngộ viễn cổ kiếm ý trong phạm vi quanh ngọn núi; về sau Hứa Lập Quốc cũng dùng khu vực này để lừa vài tu sĩ qua đường.","theLucLienQuan":["Trương gia"],"nguon":["@c0689"]},{"id":"man-suong-den-quanh-ngon-nui","name":"Màn sương đen quanh ngọn núi","cn":"","capDo":"khac","parentId":"hoanh-van-phong","blurb":"Màn sương đen quanh Hoành Vân Phong là nơi Hứa Lập Quốc ẩn nấp và trêu chọc người tới cầu kiến.","detail":"Cha con Trương Tân Hải kiêng kị màn sương đen quanh ngọn núi; Hứa Lập Quốc ẩn trong đó, dụ con trai Trương Tân Hải tiến vào và định tạm dung nhập thân thể người này.","theLucLienQuan":["Trương gia"],"nguon":["@c0689"]},{"id":"hoang-mac-tay-bac-thanh-linh-tinh","name":"Hoang mạc tây bắc Thanh Linh Tinh","cn":"","capDo":"khac","parentId":"thanh-linh-tinh","blurb":"Hoang mạc nơi Vương Lâm bố trí trận pháp tiên ngọc để trùng kích Vấn Đỉnh viên mãn.","detail":"Ở hoang mạc tây bắc Thanh Linh Tinh, Vương Lâm bày lượng lớn tiên ngọc thành trận pháp khổng lồ, thổ nạp tiên khí trong một năm rồi uống tiên dịch để tiến tới Vấn Đỉnh viên mãn.","theLucLienQuan":[],"nguon":["@c0689"]},{"id":"thanh-dan-tinh","name":"Thánh Đàn Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tu chân tinh nơi Vương Lâm chờ đoạt Lôi Đỉnh từ đội tu sĩ trở về.","detail":"Theo ngọc giản của Thân Công Hổ, nơi này có hai gia tộc thường nhận nhiều Lôi Đỉnh. Vương Lâm đến đây, dùng thần thức kiểm tra rồi ngồi chờ trong tinh không cho tới khi đội tu sĩ trở về.","theLucLienQuan":["Trương gia","Hai gia tộc tu chân trên Thánh Đàn Tinh"],"nguon":["@c0690"]},{"id":"tu-chan-tinh-cua-lao-gia","name":"Tu chân tinh của lão già","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu nơi lão già Âm Hư và tộc nhân trở về sau giao dịch.","detail":"Sau khi đổi được ba thuật của Vương Lâm, lão già trở về tinh cầu này và lập tức bế quan để chuẩn bị một tháng sau tới Lôi Tiên Giới.","theLucLienQuan":["Gia tộc của lão già Âm Hư"],"nguon":["@c0691"]},{"id":"cua-lon-loi-tien-gioi","name":"Cửa lớn Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Đích đến của các tu sĩ được lôi quang dẫn dắt khi Lôi Tiên Giới mở.","detail":"Sau khi Lôi Đỉnh vỡ, cuồng lôi cuốn Vương Lâm qua không gian dẫn tới cửa này với tốc độ vượt xa tu sĩ bình thường.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0692"]},{"id":"hu-khong-tren-duong-toi-loi-tien-gioi","name":"Hư không trên đường tới Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Không gian dẫn dắt tu sĩ tới Lôi Tiên Giới bằng lôi quang.","detail":"Tại đây, Vương Lâm bị cuồng lôi cuốn đi nhanh đến mức không dám tản thần thức, còn nhiều tu sĩ khác chỉ thấy một luồng sao băng lôi đình lao qua.","theLucLienQuan":["La Thiên Tinh Vực"],"nguon":["@c0692"]},{"id":"cua-loi-tien-gioi","name":"Cửa Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Lối vào Lôi Tiên Giới, bản chất là một đạo sấm sét đỏ sậm khổng lồ.","detail":"Cửa này nằm ở tận cùng không gian hư vô, không phải cổng vật chất. Truyền thuyết nói toàn bộ tiên hồn của Lôi Tiên Giới sau khi sụp đổ hóa thành đạo sấm sét đỏ sậm này.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0693"]},{"id":"khong-gian-hu-vo-truoc-loi-tien-gioi","name":"Không gian hư vô trước Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực các tu sĩ khoanh chân chờ trước cửa Lôi Tiên Giới.","detail":"Nhiều sứ giả Lôi Tiên Điện, độc tu và tu sĩ bước thứ hai tụ tập ở đây chờ Lôi Tiên Giới mở. Sao băng lôi đình của Vương Lâm lao qua khu vực này trước khi cửa mở.","theLucLienQuan":["Lôi Tiên Điện","Độc tu La Thiên Tinh Vực"],"nguon":["@c0693"]},{"id":"thien-la-tinh-vuc","name":"Thiên La Tinh Vực","cn":"","capDo":"vuc","parentId":"tinh-khong","blurb":"Tinh vực lưu truyền nhiều truyền thuyết về Lôi Tiên Giới.","detail":"Một truyền thuyết được nhiều người chấp nhận tại đây cho rằng cửa Lôi Tiên Giới do toàn bộ tiên hồn sau khi tiên giới sụp đổ hóa thành.","theLucLienQuan":[],"nguon":["@c0693"]},{"id":"ngon-loi-son-den-trong-loi-tien-gioi","name":"Ngọn lôi sơn đen trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi đen trên phần đại lục bị phá hủy trong Lôi Tiên Giới, có vô số cuồng lôi chạy qua.","detail":"Lão già tóc bạc xuất hiện tại đây trước khi Lôi Tiên Giới mở, cảm ứng dị biến rồi hóa thành vô số tinh điểm biến mất.","theLucLienQuan":[],"nguon":["@c0693"]},{"id":"dai-luc-phia-dong-trong-loi-tien-gioi","name":"Đại lục phía đông trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực nơi lưu tinh lôi đình nện Vương Lâm xuống, tạo hố sâu và làm địa tầng bất ổn.","detail":"Sau cú va chạm, mặt đất sụp xuống và chôn vùi Vương Lâm vào khu vực thạch thất dưới lòng đất, mở đầu tuyến giam cầm do lão giả tóc bạc can thiệp.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"thach-that-duoi-long-dat","name":"Thạch thất dưới lòng đất","cn":"","capDo":"khac","parentId":"dai-luc-phia-dong-trong-loi-tien-gioi","blurb":"Nơi Vương Lâm tỉnh lại sau khi bị vùi lấp trong Lôi Tiên Giới.","detail":"Thạch thất đã sụp đổ, xung quanh bị bùn đất chứa thiên địa nguyên lực phong tỏa. Vương Lâm thổ nạp tại đây, gọi khôi lỗi Tiên Vệ hộ pháp rồi phát hiện chỉ có phía trước có thể mở đường.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"thong-dao-duoi-long-dat","name":"Thông đạo dưới lòng đất","cn":"","capDo":"khac","parentId":"dai-luc-phia-dong-trong-loi-tien-gioi","blurb":"Lối đi quanh co phía trước thạch thất, dường như bị người khác điều khiển.","detail":"Vương Lâm dùng tiên lực hóa thành quái phong mở đường. Trong lúc dò xét, các cửa ra thông lên mặt đất liên tục lóe sáng rồi biến mất trước khi hắn tới nơi.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"hu-khong-ben-ngoai-thong-dao","name":"Hư không bên ngoài thông đạo","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khoảng hư không mà Vương Lâm lao vào sau khi vượt qua cánh cửa kế tiếp trong mạng thần thông dưới lòng đất. Đây là khu vực bên ngoài hệ thống thông đạo giam khốn tại Lôi Tiên Giới.","detail":"Sau khi thông đạo dưới lòng đất bị phá sập, cửa ra vẫn tiếp tục xuất hiện tại điểm giao thiên địa nguyên lực. Vương Lâm lợi dụng việc không còn bùn đất cản trở để cùng Tiên Vệ và Lôi Thú lao qua cửa, thoát khỏi khu vực bị nhốt và bay vào hư không bên ngoài.","theLucLienQuan":[],"nguon":["@c0695"]},{"id":"manh-dai-luc-nho-cua-loi-tien-gioi","name":"Một mảnh đại lục nhỏ của Lôi tiên giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Một mảnh đại lục nhỏ trong Lôi tiên giới là nơi lão giả tóc trắng đứng trước ngọn núi lớn để tiếp tục kế hoạch. Tại đây ông chuẩn bị thu hồn tiên sơn và bố trí La Thiên đại trận.","detail":"Sau khi nhận ra Vương Lâm đã thoát sớm bằng mánh khóe, lão giả tóc trắng vẫn ở lại trên mảnh đại lục nhỏ này. Ông đặt trọng tâm vào ngọn núi lớn cao vút trong mây, coi việc thu hồn tiên sơn là bước trước khi bố trí La Thiên đại trận.","theLucLienQuan":["La Thiên"],"nguon":["@c0696"]},{"id":"tien-son","name":"Tiên sơn","cn":"","aliases":["Ngọn núi lớn cao vút trong mây"],"capDo":"khac","parentId":"manh-dai-luc-nho-cua-loi-tien-gioi","blurb":"Tiên sơn là ngọn núi lớn cao vút trong mây mà lão giả tóc trắng muốn thu hồn. Hồn của nó liên quan trực tiếp tới việc bố trí La Thiên đại trận.","detail":"Lão giả tóc trắng đặt mục tiêu thu được hồn của tiên sơn trước khi bố trí La Thiên đại trận. Đây là mắt xích quan trọng trong kế hoạch ông đã chuẩn bị suốt mấy vạn năm.","theLucLienQuan":["La Thiên"],"nguon":["@c0696"]},{"id":"dai-luc-manh-vo-trong-loi-tien-gioi","name":"Đại lục mảnh vỡ trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh đại lục rộng lớn trong Lôi Tiên Giới, nơi Vương Lâm giao chiến và rời xa chiến trường.","detail":"Mảnh đại lục này rất rộng và vững chắc. Sau trận với Hứa Phong Hàn, Vương Lâm rời khỏi khu vực giao chiến nhiều vạn dặm, tiếp tục bay tới gần rìa đại lục để tìm nơi dưỡng thương.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"loi-son","name":"Lôi Sơn","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Ngọn núi gần rìa đại lục Lôi Tiên Giới, luôn lóe lôi quang.","detail":"Lôi Sơn có lôi đình giáng xuống và liên kết với núi. Vương Lâm chọn nơi này, khoét động phủ ở lưng chừng núi để thổ nạp, luyện hóa tiên lôi và nghiên cứu thu hoạch sau trận chiến.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"dong-phu-tren-loi-son","name":"Động phủ trên Lôi Sơn","cn":"","capDo":"khac","parentId":"loi-son","blurb":"Động phủ tạm thời do Vương Lâm mở trên lưng chừng Lôi Sơn.","detail":"Đây là nơi Vương Lâm dưỡng thương sau khi diệt Hứa Phong Hàn. Hắn luyện hóa hai đạo tiên lôi, nghiên cứu mảnh vỡ pháp bảo, kiểm tra Ma Liên và lấy được vật phẩm trong các quang châu.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"tinh-cau-do-sam-cua-dieu-gia","name":"Tinh cầu đỏ sậm của Diêu gia","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu lớn của Diêu gia trong La Thiên Tinh Vực, tỏa khí tức quỷ dị.","detail":"Diêu Không trở về tinh cầu đỏ sậm này để xin nhận tổ quy tông. Từ nơi đây vang ra giọng nói khàn khàn của tổ phụ Diêu gia, người tính ra Diêu Tích Huyết đang ở Lôi Tiên Giới.","theLucLienQuan":["Diêu gia"],"nguon":["@c0699"]},{"id":"nui-da-canh-cam-che","name":"Núi đá cạnh cấm chế","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Khu núi đá gần trận pháp cấm chế trên đại lục vỡ trong Lôi Tiên Giới. Đây là nơi gợn sóng không gian che giấu sự ẩn hiện của Lý Nguyên và nữ tu.","detail":"Bề ngoài núi đá bình thường, nhưng cạnh đó có khu vực gợn sóng không gian để hai tu sĩ ẩn nấp quan sát con mồi. Vương Lâm rời đi giả tạo rồi quay lại theo dõi, từ đó phát hiện hai người bước ra từ nơi ẩn giấu.","theLucLienQuan":["Gia tộc của nữ tu Vấn Đỉnh đại viên mãn"],"nguon":["@c0700"]},{"id":"cua-dong-duoi-cam-che","name":"Cửa động dưới cấm chế","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Hang động rộng vài trượng bị trận pháp cấm chế che giấu. Bên trong có bóng xanh hoặc thú cưng của nữ tu, có thể nuốt tu sĩ và kéo cả nguyên thần trở lại.","detail":"Cửa động chỉ lộ ra sau khi hình nhân mộc linh tự bạo phá lớp cấm chế bên ngoài. Tu sĩ trung niên vừa tiến vào đã gặp nạn, nguyên thần thoát ra cũng bị bóng xanh cuốn ngược vào trong, khiến nữ tu hưng phấn vì thú cưng đã ăn được một người.","theLucLienQuan":["Gia tộc của nữ tu Vấn Đỉnh đại viên mãn"],"nguon":["@c0700"]},{"id":"hang-dong-trong-tran-phap-cam-che","name":"Hang động trong trận pháp cấm chế","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Hang động nơi khí âm hàn xanh lục hóa thành Thiên Quỷ, nằm trong bố trí cấm chế của Lý Nguyên và Cát Hồng.","detail":"Sau khi phá tan mười tám cấm chế, Vương Lâm tiến vào hang và nhận ra khí âm hàn xanh lục bên trong chính là Thiên Quỷ. Đây là nơi đối phương dùng để mai phục nhưng cuối cùng Thiên Quỷ bị thu vào Tôn Hồn Phiên.","theLucLienQuan":["Cát gia"],"nguon":["@c0701"]},{"id":"bi-dia-co-cam-che-trong-loi-tien-gioi","name":"Bí địa có cấm chế trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Nơi bí ẩn do bản đồ cổ của Lý Nguyên chỉ dẫn, được cho là còn cấm chế và vật bảo tồn nguyên vẹn.","detail":"Lý Nguyên dùng tin tức về bí địa này để chuộc lỗi với Vương Lâm. Theo lời hắn, nơi đó tồn tại từ trước khi Lôi Tiên Giới sụp đổ, có cấm chế bao phủ, có nguyên khí và có thể còn tiên bảo hoặc vật chưa bị phá hủy.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"ria-dai-luc-loi-tien-gioi","name":"Rìa đại lục Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mép mảnh đại lục bị xé rách, phía dưới là hư vô và phía ngoài có các sợi xích lôi quang kéo dài.","detail":"Sau vài ngày bay, ba người tới rìa đại lục. Từ đây có thể nhìn thấy khoảng hư vô tối đen và các đạo lôi quang như xích sắt nối sang những mảnh đại lục khác trong Lôi Tiên Giới.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"soi-xich-loi-quang","name":"Sợi xích lôi quang","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Những đạo lôi quang nối các mảnh đại lục vỡ của Lôi Tiên Giới, vừa là đường định hướng vừa chứa lôi đình mạnh mẽ.","detail":"Tu sĩ đi trong hư vô có thể men theo những sợi xích lôi quang để không lạc hướng. Cát Hồng dùng thiết kiếm tạo quầng sáng đi qua, còn Vương Lâm trực tiếp bước trên xích lôi, hấp thu lôi quang bằng thân thể và nguyên thần có lôi uy.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"hu-vo-trong-loi-tien-gioi","name":"Hư vô trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực hư vô nơi nhóm Vương Lâm đi sâu bằng thiết kiếm và thân pháp. Lôi quang tại đây càng lúc càng dày đặc, đồng thời truyền tới chấn động bất thường từ phía trước.","detail":"Trong hư vô của Lôi Tiên Giới, Vương Lâm, Lý Nguyên và Cát Hồng phi hành gần hai tháng mà không gặp tu sĩ nào. Càng đi sâu, lôi quang càng nồng đậm, sợi xích lôi đình bắt đầu chấn động dữ dội và dẫn nhóm tới đám sương mù cấm chế chắn đường.","theLucLienQuan":[],"nguon":["@c0702"]},{"id":"dam-suong-mu-tien-khi-chan-duong","name":"Đám sương mù tiên khí chắn đường","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Vùng sương mù vô biên chắn toàn bộ đường đi trong Lôi Tiên Giới. Bên trong chứa cấm chế thiên cấp trung phẩm và là nơi lão già bí ẩn bước ra cuối chương.","detail":"Sau khi quyết định tiến về phía trước, Vương Lâm phát hiện một đám sương mù tiên khí khổng lồ chắn ngang toàn bộ đường đi. Lý Nguyên xác định đây là cấm chế, sau đó nhận ra nó thuộc thiên cấp trung phẩm và hình thành đại trận luyện hóa vạn vật; cuối chương, một lão già cầm sợi xích lôi quang bước ra từ chính vùng sương mù này.","theLucLienQuan":[],"nguon":["@c0702"]},{"id":"trung-tam-dai-luc-loi-tien-gioi","name":"Trung tâm đại lục","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Khu vực trung tâm của đại lục trong Lôi tiên giới, nơi Lý Nguyên dừng lại đối chiếu địa hình.","detail":"Sau một tháng phi hành, Lý Nguyên tới trung tâm đại lục để quan sát và so sánh với hình ảnh trong đầu. Từ đó hắn xác định cấm chế không ở tại đây mà nằm đại khái về phía đông.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"phia-dong-dai-luc-loi-tien-gioi","name":"Phía đông đại lục","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Hướng Lý Nguyên xác định là nơi đại khái có cấm chế cần tìm trên đại lục Lôi tiên giới.","detail":"Sau khi rời trung tâm đại lục, Lý Nguyên dẫn Vương Lâm và Cát Hồng bay về phía đông. Hành trình này kéo dài ba tháng, vượt qua hư vô và một mảnh đại lục trước khi tới địa điểm cuối cùng.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"loi-quang-thien-lien-trong-hu-vo","name":"Lôi quang Thiên liên trong hư vô","cn":"","capDo":"khac","parentId":"hu-vo-trong-loi-tien-gioi","blurb":"Khu vực hư vô có Lôi quang Thiên liên mà ba người xuyên qua trên đường tới phía đông đại lục.","detail":"Trong hành trình ba tháng từ trung tâm đại lục tới nơi cấm chế, Vương Lâm, Lý Nguyên và Cát Hồng một lần nữa xâm nhập vùng Lôi quang Thiên liên trong hư vô rồi tiếp tục vượt qua một mảnh đại lục.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"ngon-nui-cao-vut-trong-may","name":"Ngọn núi cao vút trong mây","cn":"","capDo":"khac","parentId":"phia-dong-dai-luc-loi-tien-gioi","blurb":"Địa điểm Lý Nguyên nhìn thấy ở cuối hành trình và kích động xác nhận là nơi cần tìm.","detail":"Sau ba tháng phi hành về phía đông, Lý Nguyên nhìn chằm chằm ngọn núi cao vút trong mây và không giấu được kích động. Đây là điểm đến gắn với cấm chế mà hắn tìm kiếm trên đại lục trong Lôi tiên giới.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"ngon-nui-vo-danh-trong-loi-tien-gioi","name":"Ngọn núi vô danh trong Lôi tiên giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi cực cao trong Lôi tiên giới, sấm chớp bao quanh và cấm chế dày đặc. Lý Nguyên nói sâu trong núi có chủ nhân của hắn, đồng thời dùng nơi này để gây sức ép với Vương Lâm.","detail":"Ngọn núi mang dấu vết năm tháng, có nhiều cấm chế chưa bị bài trừ hoàn toàn dù Lôi tiên giới từng mở ra nhiều lần. Một con đường lên núi lộ ra nhờ các lớp cấm chế bị người đời trước phá dần; tại đây Lý Nguyên định giữ Vương Lâm lại, nhưng Vương Lâm dùng Tiên Vệ khôi lỗi mở dòng chảy thông ra ngoài.","theLucLienQuan":["Lôi tiên giới","Cát gia"],"nguon":["@c0705"]},{"id":"tien-phu-o-manh-dat-yeu-linh","name":"Tiên phủ ở mảnh đất Yêu Linh","cn":"","capDo":"khac","parentId":null,"blurb":"Tiên phủ tại mảnh đất Yêu Linh, nơi Vương Lâm từng lần đầu nhìn thấy dấu vết Mai hoa thuật còn sót lại. Ký ức này giúp hắn liên hệ cấm chế của Lý Nguyên với Mai hoa thuật.","detail":"Khi yêu cầu Mai hoa thuật từ Lý Nguyên, Vương Lâm nhớ lại mình từng thấy dấu vết còn sót của pháp môn này trong tiên phủ ở mảnh đất Yêu Linh. Đây là cơ sở quan trọng khiến hắn xem Mai hoa thuật là mục tiêu thật sự trong chuyến đi cùng Lý Nguyên.","theLucLienQuan":[],"nguon":["@c0705"]},{"id":"ngon-nui-do-tu-dai-cam-thuat-tan-vo-tao-thanh","name":"Ngọn núi do tứ đại cấm thuật tan vỡ tạo thành","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi đặc biệt trong Lôi Tiên Giới được Lý Nguyên nói là do tứ đại cấm thuật tan vỡ tạo thành. Nếu không biết cách hóa giải, người vào núi sẽ không thấy điểm cuối.","detail":"Lý Nguyên đưa Vương Lâm tới ngọn núi này để tìm đến nơi cất giấu bí mật liên quan chủ nhân hắn. Hắn dùng cấm chế và phương pháp hóa giải khiến ngọn núi nhiều lần chấn động, thu nhỏ dần, cuối cùng để lộ đỉnh núi.","theLucLienQuan":["Cát gia"],"nguon":["@c0706"]},{"id":"dinh-nui-cam-thuat","name":"Đỉnh núi","cn":"","capDo":"khac","parentId":"ngon-nui-do-tu-dai-cam-thuat-tan-vo-tao-thanh","blurb":"Đỉnh núi là nơi hiện ra tượng đá trung niên nam tử, thanh phi kiếm và người đứng trên mũi kiếm. Đây là điểm Lý Nguyên hướng tới và nơi Vương Lâm bị kéo vào huyễn cảnh.","detail":"Sau khi Lý Nguyên nhiều lần phá cấm và thu nhỏ ngọn núi, đỉnh núi xuất hiện trong tầm mắt. Tại đây có tượng đá cao lớn cùng thanh phi kiếm, trên mũi kiếm có một người, và ấn quyết trên tượng đá dẫn Vương Lâm vào cảnh tượng Tiên giới xa xưa.","theLucLienQuan":[],"nguon":["@c0706"]},{"id":"chien-truong-tien-gioi-trong-huyen-canh","name":"Chiến trường Tiên giới trong huyễn cảnh","cn":"","capDo":"khac","parentId":"dinh-nui-cam-thuat","blurb":"Chiến trường Tiên giới trong huyễn cảnh là không gian Vương Lâm nhìn thấy khi bị ấn quyết trên tượng đá hút tâm thần. Nơi đó có tiên nhân lôi điện giao chiến, bảo kiếm tím và cảnh chủ nhân trên chuôi kiếm tan rã.","detail":"Trong huyễn cảnh, Vương Lâm thấy nhiều tiên nhân lượn lờ, quanh người có lôi điện, thỉnh thoảng có người nổ tung mà chết dù không thấy địch nhân. Sau đó thanh bảo kiếm tím xuất hiện, chở nam tử trên chuôi kiếm và người hầu trên mũi kiếm, tái hiện cảnh chủ chết, đầy tớ đi theo.","theLucLienQuan":["Tiên giới"],"nguon":["@c0706"]},{"id":"tinh-vuc-lien-minh","name":"Tinh vực Liên Minh","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực nơi tổ tiên Lý gia dùng thuật cấm chế trao đổi với một tu sĩ đại thần thông để lấy họa trục.","detail":"Trong kế hoạch phá nô ấn, tổ tiên thiên tài của Lý gia từng đi tới tinh vực Liên Minh và đổi được họa trục, một trong ba pháp khí then chốt dùng để giải phong ấn.","theLucLienQuan":["Lý gia"],"nguon":["@c0707"]},{"id":"tinh-vuc-van-tran","name":"Tinh vực Vân Trần","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực có Phong tiên giới, nơi tổ tiên Lý gia đổi lấy la bàn.","detail":"Tổ tiên thiên tài của Lý gia tới tinh vực Vân Trần, dùng tích súc gia tộc ở Phong tiên giới để đổi lấy la bàn phục vụ kế hoạch hóa giải nô ấn.","theLucLienQuan":["Lý gia"],"nguon":["@c0707"]},{"id":"phong-tien-gioi","name":"Phong tiên giới","cn":"","capDo":"gioi-nho","parentId":"tinh-vuc-van-tran","blurb":"Địa điểm thuộc tinh vực Vân Trần, nơi tổ tiên Lý gia đổi lấy la bàn.","detail":"Phong tiên giới là nơi tổ tiên Lý gia dùng tích súc gia tộc để đổi được la bàn, pháp khí dùng để ngưng ấn trong kế hoạch phá nô ấn.","theLucLienQuan":["Lý gia"],"nguon":["@c0707","@c0747"]},{"id":"ngon-nui-co-tuong-da","name":"Ngọn núi có tượng đá","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi trong Lôi Tiên giới nơi có tượng đá và nhiều cấm chế.","detail":"Đây là nơi Lý Nguyên dùng Cát Hồng, thiết kiếm, la bàn, bình ngọc, họa trục cùng oán khí để tế luyện tượng đá; Vương Lâm nhận ra nghi thức này có thể nhằm khiến tiên nhân trong tượng đá sống lại.","theLucLienQuan":["Lý gia","Cát gia"],"nguon":["@c0708"]},{"id":"vien-co-tien-gioi","name":"Viễn cổ tiên giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Viễn cổ tiên giới là cảnh tượng ký ức hoặc ảo ảnh Vương Lâm từng chứng kiến, gắn với tiên kiếm bay lên trời và hai thân ảnh đứng trên kiếm. Chương này tiếp tục để ngỏ ranh giới thực giả của cảnh tượng ấy.","detail":"Sau khi tượng đá vỡ nát và thanh kiếm khói xanh xuất hiện, Vương Lâm vẫn không thể phân định hoàn toàn đâu là thật, đâu là giả trong những hình ảnh viễn cổ tiên giới. Nơi này liên quan tới chủ nhân tiên nhân, người đầy tớ, thanh tiên kiếm và bí ẩn kéo dài từ huyễn cảnh trước đó.","theLucLienQuan":[],"nguon":["@c0710"]},{"id":"manh-dai-luc-hoang-vu","name":"Mảnh đại lục hoang vu","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh đại lục hoang vu trong Lôi tiên giới là nơi Vương Lâm và Lý Nguyên phát hiện tiên cấm lấy bùn đất làm chính. Khu vực có đất đen, bầu trời âm u, tiếng sấm vang vọng và không có người khác trong phạm vi ngàn dặm.","detail":"Tại mảnh đại lục này, Lý Nguyên nhận ra cấm chế che giấu cảnh tượng thật bên dưới. Sau khi phá cấm, mặt đất sụp xuống và lộ ra một ngọn núi có cung điện rách nát cùng dấu vết nơi trồng tiên thảo từng bị đào sạch.","theLucLienQuan":[],"nguon":["@c0710"]},{"id":"cung-dien-tren-tien-son","name":"Cung điện trên tiên sơn","cn":"","capDo":"khac","parentId":"tien-son","blurb":"Cung điện trên tiên sơn là điện phủ tiên nhân rách nát lộ ra sau khi Lý Nguyên phá tiên cấm. Phía sau cung điện có cái cây bất thường và dưới tán cây có hai bộ hài cốt.","detail":"Cung điện hoa lệ đã bị phá hoại, thủng lỗ chỗ và không còn tiên thảo ở khu vực trồng phía trước. Điểm bất thường nằm ở cái cây phía sau, nơi bên trái chuyển động còn bên phải bất động; khi tới gần, Vương Lâm và Lý Nguyên phát hiện hai bộ hài cốt, một bộ mặc bộ giáp da đặc biệt.","theLucLienQuan":[],"nguon":["@c0710"]},{"id":"tu-duong-truyen-thua-cua-ly-gia","name":"Từ đường truyền thừa của Lý gia","cn":"","capDo":"khac","parentId":null,"blurb":"Từ đường truyền thừa của Lý gia là nơi Lý Nguyên nói sẽ đưa Vương Lâm tới sau khi rời Lôi tiên giới. Tại đây hắn hứa truyền Phá Diệt cấm và chia một nửa tâm cấm.","detail":"Đây là địa điểm giữ phần truyền thừa cấm chế then chốt của Lý gia, đặc biệt là Phá Diệt cấm và tâm cấm chỉ truyền cho gia chủ mỗi đời. Lời hứa của Lý Nguyên biến nơi này thành điểm đến quan trọng trong tuyến cấm chế của Vương Lâm.","theLucLienQuan":["Lý gia"],"nguon":["@c0710"]},{"id":"khu-vuc-cai-cay-va-truyen-tong-tran","name":"Khu vực cái cây và truyền tống trận","cn":"","capDo":"khac","parentId":"manh-dai-luc-nho-cua-loi-tien-gioi","blurb":"Điểm đặt huyễn cấm trên đại lục nhỏ, ban đầu hiện ra cây cối, hài cốt và giáp da. Sau khi Lý Nguyên phá cấm, nơi này lộ ra truyền tống trận phát sáng dịu.","detail":"Khu vực này dùng cảnh cây cối và hài cốt để che giấu truyền tống trận bên dưới. Khi huyễn cấm bị phá, truyền tống trận tiếp xúc ngoại giới và tiên khí nên xuất hiện dòng xoáy nhỏ ở mép trận, trở thành lối thoát gấp của Vương Lâm và Lý Nguyên trước đợt truy sát bằng thần thức.","theLucLienQuan":[],"nguon":["@c0711"]},{"id":"khong-gian-tru-vat-cua-tien-nhan","name":"Không gian trữ vật của tiên nhân","aliases":["trữ vật không gian","Trữ vật không gian của Tiên nhân vô danh"],"cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian u ám do tiên nhân đã chết mở ra, nơi Vương Lâm và Lý Nguyên truyền tống tới sau khi thoát Huyết Tổ.","detail":"Không gian này có tế đàn, núi, thung lũng, bầu trời thấp và nhiều khe nứt nguy hiểm có thể nuốt thần thức. Lý Nguyên xác định nơi đây không phải mảnh vỡ đại lục bên ngoài mà là không gian trữ vật của một tiên nhân đã chết, đang suy yếu và có thể sụp đổ nếu bị quấy nhiễu từ bên ngoài.","theLucLienQuan":["Tiên nhân"],"nguon":["@c0712","@c0727"]},{"id":"te-dan-nau-trong-khong-gian-tru-vat","name":"Tế đàn nâu cao khoảng mười trượng","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Tế đàn nơi truyền tống đưa Vương Lâm và Lý Nguyên tới trong không gian trữ vật tiên nhân.","detail":"Tế đàn màu nâu cao khoảng mười trượng, có bậc thang tàn phá và nhiều vết nứt kéo lên đến đỉnh. Vương Lâm cùng Lý Nguyên xuất hiện tại đây sau khi lao vào truyền tống trận để thoát Huyết Tổ.","theLucLienQuan":[],"nguon":["@c0712"]},{"id":"hai-day-nui-ba-thung-lung-trong-khong-gian-tru-vat","name":"Hai dãy núi, ba thung lũng trong không gian trữ vật","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Bố cục chính của không gian trữ vật tiên nhân do Lý Nguyên quan sát được từ trên cao.","detail":"Khi bay lên cao quan sát, Lý Nguyên nhận ra trong không gian trữ vật có hai dãy núi và ba thung lũng. Cấu trúc này trở thành cơ sở để Vương Lâm và Lý Nguyên vừa sưu tầm vật bên trong vừa cân nhắc bố trí cạm bẫy đối phó Huyết Tổ.","theLucLienQuan":[],"nguon":["@c0712"]},{"id":"thung-lung-thu-nhat-trong-khong-gian-tru-vat","name":"Thung lũng thứ nhất","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Thung lũng đầu tiên Vương Lâm và Lý Nguyên khảo sát trong không gian trữ vật tiên nhân.","detail":"Lối vào thung lũng rộng vài trượng, ban đầu chỉ có sương mù mỏng. Sau khi lớp cấm chế bề ngoài bị phá, Vương Lâm vẫn cẩn thận sai Tiên vệ dò đường, khiến cấm chế thật sự bên trong bùng lên thành mũi tên sương mù tấn công.","theLucLienQuan":[],"nguon":["@c0712","@c0713"]},{"id":"thung-lung-thu-hai-trong-khong-gian-tru-vat","name":"Thung lũng thứ hai","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Thung lũng sau vùng khe nứt dày đặc, có quầng sáng vô hình ở lối vào.","detail":"Lối vào thung lũng có bóng ma và điểm sáng gần như trong suốt nuốt cấm chế. Bên trong phủ đầy hài cốt, có tám đoản kiếm cùng đầu thú lớn bốn gai xương.","theLucLienQuan":[],"nguon":["@c0713"]},{"id":"thung-lung-thu-ba-trong-khong-gian-tru-vat","name":"Thung lũng thứ ba","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Thung lũng nơi Vương Lâm tìm thấy miếu tàn phá, hai bộ xương và giáp da Cổ Thần.","detail":"Sau chấn động dãy núi, cấm chế ở lối vào thung lũng thứ ba suy sụp nhiều chỗ. Bên trong có miếu cổ, hai hài cốt và manh mối về chiến tranh cổ xưa qua tranh vẽ.","theLucLienQuan":["Cổ Thần","Tiên giới"],"nguon":["@c0714"]},{"id":"day-nui-trong-khong-gian-tru-vat","name":"Dãy núi trong không gian trữ vật","cn":"","capDo":"khac","parentId":"khong-gian-tru-vat-cua-tien-nhan","blurb":"Dãy núi bị Vương Lâm nhận định là được dời từ ngoài vào.","detail":"Vương Lâm và Tiên vệ lợi dụng bản chất không tự nhiên của dãy núi để lay chuyển nó, khiến thung lũng chứa đầu thú chấn động và phá thế vây sát.","theLucLienQuan":[],"nguon":["@c0714"]},{"id":"ngoi-mieu-trong-thung-lung-thu-ba","name":"Ngôi miếu trong thung lũng thứ ba","cn":"","capDo":"khac","parentId":"thung-lung-thu-ba-trong-khong-gian-tru-vat","blurb":"Miếu nhỏ tàn phá, không còn cửa, nằm trong thung lũng thứ ba.","detail":"Tầng thứ nhất trống rỗng nhưng trên bốn vách có chín bức tranh vẽ người khổng lồ trán tám chấm bị vô số Tiên nhân công kích.","theLucLienQuan":["Cổ Thần","Tiên giới"],"nguon":["@c0714"]},{"id":"tang-mot-mieu-tho","name":"Tầng một miếu thờ","cn":"","capDo":"khac","parentId":"ngoi-mieu-trong-thung-lung-thu-ba","blurb":"Tầng có các bức tranh được Lý Nguyên xem và thu đi.","detail":"Vương Lâm quay xuống tầng này sau khi hủy trang giấy ở tầng hai và cảnh báo Lý Nguyên phải giữ kín tranh.","theLucLienQuan":[],"nguon":["@c0715"]},{"id":"tang-hai-mieu-tho","name":"Tầng hai miếu thờ","cn":"","capDo":"khac","parentId":"ngoi-mieu-trong-thung-lung-thu-ba","blurb":"Tầng đặt bàn, giấy vàng, bút vẽ, lư hương và quỹ xích.","detail":"Vương Lâm đọc di bút của Tiên nhân vô danh tại đây, biết về trận Cổ Thần thắng chư tiên, cái chết dị thường của Tiên đế và nỗi sợ của người viết.","theLucLienQuan":["Tiên giới","Cổ Thần"],"nguon":["@c0715"]},{"id":"manh-vo-dai-luc-giau-tui-tru-vat","name":"Mảnh vỡ đại lục nơi Vương Lâm giấu túi trữ vật","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh vỡ xa lạ trong Lôi chi Tiên giới nơi Vương Lâm chôn túi trữ vật của Diêu Tích Tuyết.","detail":"Vương Lâm dò xét vài ngày, chọn dãy núi không có dị thường, độn xuống sâu dưới đất và bố trí cấm chế quanh túi trữ vật.","theLucLienQuan":[],"nguon":["@c0716"]},{"id":"day-nui-giau-tui-tru-vat","name":"Dãy núi giấu túi trữ vật","cn":"","capDo":"khac","parentId":"manh-vo-dai-luc-giau-tui-tru-vat","blurb":"Dãy núi được Vương Lâm chọn để chôn túi trữ vật của Diêu Tích Tuyết.","detail":"Túi trữ vật bị đặt sâu dưới lòng đất và phủ cấm chế để giảm khả năng bị Huyết Tổ truy tung.","theLucLienQuan":[],"nguon":["@c0716"]},{"id":"manh-vo-dai-luc-ban-the-vuong-lam-an-nap","name":"Mảnh vỡ đại lục nơi bản thể Vương Lâm ẩn nấp","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh vỡ mà Vương Lâm dùng làm điểm giấu bản thể trong kế nghi binh.","detail":"Bản thể ẩn sâu dưới lòng đất bằng quả cầu cấm chế, còn Tiên vệ mang nguyên thần ra ngoài phóng khí tức để dụ Huyết Tổ.","theLucLienQuan":[],"nguon":["@c0716"]},{"id":"xich-sat-hu-vo","name":"Xích sắt hư vô","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Tuyến nối giữa các mảnh vỡ đại lục trong Lôi chi Tiên giới.","detail":"Vương Lâm men theo xích sắt hư vô suốt một tháng để đổi mảnh vỡ, Huyết Tổ cũng di chuyển qua hư vô và các tuyến nối này khi truy tìm.","theLucLienQuan":[],"nguon":["@c0716"]},{"id":"manh-vo-dai-luc-chien-truong-huyet-to","name":"Mảnh vỡ đại lục","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Chiến trường nơi Huyết Tổ giáng lâm và Vương Lâm dùng Tiên vệ đối đầu.","detail":"Mây máu phủ bầu trời, thần thức bước thứ hai ép đại lục mơ hồ sụp đổ; bản thể Vương Lâm ẩn trong lòng đất, còn thân Tiên vệ đối diện Huyết Tổ bên ngoài.","theLucLienQuan":[],"nguon":["@c0717"]},{"id":"hu-vo-ranh-gioi-dai-luc","name":"Hư vô ranh giới đại lục","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực Vương Lâm bỏ chạy sau khi tung truyền tống trận.","detail":"Huyết Tổ cắt đứt xích sắt lôi quang tại đây và dùng biển máu luyện hóa Tiên vệ trong hư vô.","theLucLienQuan":[],"nguon":["@c0717"]},{"id":"long-dat-manh-vo-dai-luc","name":"Lòng đất của mảnh vỡ đại lục","cn":"","capDo":"khac","parentId":"manh-vo-dai-luc-chien-truong-huyet-to","blurb":"Nơi bản thể Vương Lâm ẩn nấp trước khi bị huyết quang truy tới.","detail":"Khi huyết quang của Huyết Tổ xuyên tới, hồng quang dưới đất ngưng thành châm đỏ, buộc bản thể Vương Lâm mở mắt và kích hoạt quả cầu cấm chế.","theLucLienQuan":[],"nguon":["@c0717"]},{"id":"hu-vo-loi-tien-gioi","name":"Hư vô Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Vùng hư vô trong Lôi Tiên Giới nơi các huyết cầu Huyết Tổ dung hợp và Vương Lâm giao chiến.","detail":"Tại đây Vương Lâm bị huyết thân Huyết Tổ đánh văng, sau đó rơi vào một mảnh vỡ đại lục nhỏ.","theLucLienQuan":[],"nguon":["@c0719"]},{"id":"tinh-cau-bo-di-phat-loi-quang","name":"Tinh cầu bỏ đi phát lôi quang","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tinh cầu trong Liên minh Tinh vực nơi bản tôn Vương Lâm tu luyện trước khi xuất quan.","detail":"Sâu trong tinh cầu có hang động đá vôi thiên nhiên tràn lôi quang, nơi bản tôn tóc đỏ cảm ứng phân thân gặp nạn.","theLucLienQuan":[],"nguon":["@c0719"]},{"id":"hang-dong-da-voi-thien-nhien","name":"Hang động đá vôi thiên nhiên","cn":"","capDo":"khac","parentId":"tinh-cau-bo-di-phat-loi-quang","blurb":"Hang động sâu trong tinh cầu bỏ đi phát lôi quang, nơi bản tôn Vương Lâm ngồi tu luyện.","detail":"Bản tôn mở mắt tại đây khi biết phân thân bị Huyết Tổ ép hôn mê rồi lao ra khỏi lòng đất.","theLucLienQuan":[],"nguon":["@c0719"]},{"id":"huyet-cac-map","name":"Huyết các","cn":"","capDo":"khac","parentId":"huyet-tinh","blurb":"Cấm địa trên Huyết Tinh, phía sau tế đàn nơi Tử Tâm canh giữ.","detail":"Bên trong mở ra con đường đỏ ăn mòn thân thể và nguyên thần Tử Tâm; sau đó bị Vương Lâm nhổ cả nền đất mang đi.","theLucLienQuan":["Huyết Tinh dưới Huyết Tổ"],"nguon":["@c0720"]},{"id":"tinh-khong-tren-duong-toi-huyet-tinh","name":"Tinh không trên đường tới Huyết Tinh","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Vùng không gian nơi bản tôn Vương Lâm thu gom đá vụn trước khi tấn công Huyết Tinh.","detail":"Một vài tu sĩ chứng kiến hình thể trăm trượng của hắn tại đây và kinh hãi bỏ chạy.","theLucLienQuan":[],"nguon":["@c0720"]},{"id":"te-dan-ngoai-huyet-cac","name":"Tế đàn ngoài Huyết các","cn":"","capDo":"khac","parentId":"huyet-cac-map","blurb":"Nơi Tử Tâm ngồi lo lắng trước khi Huyết Tinh rối loạn.","detail":"Các lão già áo đỏ tới đây báo tin Huyết nô chết hàng loạt và công khai rời bỏ Huyết Tinh.","theLucLienQuan":["Huyết Tinh dưới Huyết Tổ"],"nguon":["@c0720"]},{"id":"luc-cap-tu-chan-tinh","name":"Lục cấp Tu Chân Tinh","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tu Chân Tinh cấp sáu nơi bản tôn Vương Lâm ẩn giấu khí tức sau khi mang Huyết Các rời đi.","detail":"Bản tôn chui vào tinh cầu này khoanh chân, ổn định cảm ứng với phân thân và che giấu hành tung sau khi Huyết Tinh bị phá.","theLucLienQuan":[],"nguon":["@c0721"]},{"id":"manh-luc-dia-troi-trong-hu-khong","name":"Mảnh lục địa trôi trong hư không","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh lục địa nhỏ trong Lôi Tiên Giới nơi Vương Lâm hôn mê và Thiên Kiếp giáng xuống.","detail":"Tầng mây sét bao phủ suốt một tháng, khiến rìa lục địa tan rã còn bên trong dần được luyện hóa thành phôi pháp bảo.","theLucLienQuan":[],"nguon":["@c0721"]},{"id":"manh-luc-dia-trong-tang-may","name":"Mảnh lục địa trong tầng mây","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh lục địa nơi Vương Lâm đứng độ kiếp giữa tầng mây.","detail":"Mảnh lục địa bị thiên uy và sấm sét làm rìa tiếp tục tan vỡ; khi càng nhỏ lại, nó càng trở nên kiên cố dưới kiếp lôi.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0722"]},{"id":"tang-may-bon-phia","name":"Tầng mây bốn phía","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Không gian kiếp vân bao phủ quanh mảnh lục địa.","detail":"Tầng mây bốn phía cuồn cuộn, ngưng tụ sấm sét màu đen và sấm sét bảy màu, ép thiên uy xuống thân Vương Lâm.","theLucLienQuan":[],"nguon":["@c0722"]},{"id":"tang-may-thien-kiep","name":"Tầng mây Thiên Kiếp","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Tầng mây Thiên Kiếp là chiến trường nơi Vương Lâm phản kích và giao chiến với Huyết Tổ.","detail":"Không gian này đầy sấm sét bảy màu; Vương Lâm chủ động xông vào thôn phệ mây, hấp thu lôi lực, còn Huyết Tổ bị kiếp lực áp chế khi lao vào ngăn cản.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0723"]},{"id":"manh-luc-dia-duoi-thien-kiep","name":"Mảnh lục địa dưới Thiên Kiếp","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh lục địa nơi Vương Lâm ban đầu đứng chịu sấm sét bảy màu.","detail":"Dưới sức oanh kích của Thiên Kiếp, mảnh lục địa tan rã dần, cuối cùng chỉ còn chưa tới nghìn trượng.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0723"]},{"id":"hu-vo-truy-sat-huyet-to","name":"Hư vô","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Hư vô là hướng Vương Lâm lao đi sau khi thu mảnh đất để truy sát nguyên thần Huyết Tổ.","detail":"Sau khi Thiên Kiếp tan và thu chiến lợi phẩm, Vương Lâm phóng vào hư vô, tản thần thức tìm nguyên thần Huyết Tổ với ý định nhổ cỏ tận gốc.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0724"]},{"id":"cac-dai-luc-nho-trong-loi-tien-gioi","name":"Các đại lục nhỏ trong Lôi tiên giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Những vùng đất rải rác trong Lôi tiên giới, nơi có động phủ tiên nhân, di tích và cấm chế.","detail":"Trong nửa tháng sau khi Lý Nguyên thoát nô ấn, Vương Lâm và Lý Nguyên đi qua nhiều đại lục nhỏ để tìm động phủ, di tích và cấm chế tiên nhân. Có nơi cấm chế quá lớn hoặc quá kín đáo nên dù Lôi tiên giới từng mở nhiều lần, tu sĩ vẫn khó đụng tới.","theLucLienQuan":["Lôi tiên giới"],"nguon":["@c0710"]},{"id":"manh-dai-luc-dat-den","name":"Mảnh đại lục đất đen","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực hoang vu trong Lôi tiên giới, mặt đất đen, trời âm u và có tiếng sấm nhưng không thấy lôi điện.","detail":"Đây là nơi Vương Lâm và Lý Nguyên nghiên cứu tiên cấm. Bùn đất màu đen che giấu biến hóa cấm chế, sau khi Lý Nguyên phá cấm thì mặt đất sụp xuống và lộ ra tiên sơn bị che giấu.","theLucLienQuan":["Lôi tiên giới"],"nguon":["@c0710"]},{"id":"tien-son-bi-che-giau","name":"Tiên sơn bị che giấu","cn":"","capDo":"khac","parentId":"manh-dai-luc-dat-den","blurb":"Ngọn núi hiện ra sau khi tiên cấm bị phá, không cao nhưng có cung điện hoa lệ đã rách nát trên sườn núi.","detail":"Tiên sơn vốn bị tiên cấm che phủ dưới lớp bùn đất và cảnh vật giả. Khi hiện ra, nơi này đã bị người khác khai phá trước, tiên thảo bị đào mất, chỉ còn cây cối tầm thường và cung điện hư hại.","theLucLienQuan":["Lôi tiên giới"],"nguon":["@c0710"]},{"id":"tang-quyet-cac","name":"Tàng Quyết Các","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Nơi cất giữ Tiên thuật trong Lôi chi Tiên giới, do Tiên Đế và thủ hạ tạo ra.","detail":"Tàng Quyết Các nằm trên mảnh vỡ đại lục bị bốn đại gia tộc tu chân truyền thừa từ Tiên giới phong ấn. Bên trong có quy tắc riêng, việc lấy Tiên thuật tùy cơ duyên, là mục tiêu Diêu gia tiến vào Lôi chi Tiên giới và cũng trở thành mục tiêu mới của Vương Lâm.","theLucLienQuan":["Diêu gia","Bốn đại gia tộc tu chân truyền thừa từ Tiên giới","Tiên giới"],"nguon":["@c0727"]},{"id":"manh-vo-dai-luc-bi-phong-an","name":"Mảnh vỡ đại lục bị phong ấn","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ trong Lôi chi Tiên giới chứa Tàng Quyết Các và bị bốn đại gia tộc phong ấn.","detail":"Mảnh vỡ đại lục này nằm trong Lôi chi Tiên giới, bị bốn đại gia tộc tu chân truyền thừa từ Tiên giới liên thủ phong ấn vì chứa Tàng Quyết Các, nơi cất giữ Tiên thuật.","theLucLienQuan":["Bốn đại gia tộc tu chân truyền thừa từ Tiên giới","Diêu gia"],"nguon":["@c0727"]},{"id":"di-tich-dan-tien-khi","name":"Di tích Dẫn Tiên Khí","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Thành trì hoang tàn bị che dưới cấm chế trên bình nguyên, có bia đá khắc ba chữ Dẫn Tiên Khí.","detail":"Lý Nguyên dùng cấm chế gia truyền bóc lớp che phủ bình nguyên, để lộ thành trì hoang tàn và bia đá Dẫn Tiên Khí. Di tích này được dùng làm ví dụ cho dấu tích Tiên thuật mà Tâm Cấm thuật có thể đảo nghịch.","theLucLienQuan":["Lý gia","Tiên giới"],"nguon":["@c0727"]},{"id":"dan-co-phu","name":"Dẫn Cơ phủ","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Khu phủ giao dịch hoang tàn trong Lôi chi Tiên giới, quy mô gần như thành trì nhân gian. Nơi đây có nhiều cửa hàng đổ nát và che giấu một tiên trận dẫn tới mật thất.","detail":"Dẫn Cơ phủ từng là địa điểm giao dịch của Tiên nhân khi Lôi chi Tiên giới chưa sụp đổ. Sau nhiều lần bị người tiến vào tìm kiếm, nơi này chỉ còn bia đá và phế tích; tại khu phía đông, Lý Nguyên tìm ra dấu vết cửa hàng lớn nhất và trận pháp mật thất ẩn dưới đống đổ nát.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0728"]},{"id":"khu-phia-dong-dan-co-phu","name":"Khu phía đông Dẫn Cơ phủ","cn":"","capDo":"khac","parentId":"dan-co-phu","blurb":"Khu vực Lý Nguyên suy đoán từng có cửa hàng lớn nhất của Dẫn Cơ phủ. Bên dưới đống vách đổ ở đây ẩn giấu tiên trận dẫn tới hắc động.","detail":"Sau khi khảo sát Dẫn Cơ phủ mà chưa thấy gì bất thường, Lý Nguyên chuyển hướng tới phía đông vì cho rằng cửa hàng lớn nhất thường nằm ở đó. Vương Lâm công kích vị trí hắn chỉ, phá vỡ vách đổ và khiến đồ án trận pháp hiện ra trên mặt đất.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0728"]},{"id":"manh-vo-dai-luc-dan-co-phu","name":"Mảnh vỡ đại lục","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ đại lục trong Lôi chi Tiên giới nơi Dẫn Cơ phủ tọa lạc. Cột sáng tiết linh từ tiên trận khiến tu chân giả trên toàn vùng nhìn thấy và lần lượt kéo tới.","detail":"Dẫn Cơ phủ nằm trên một mảnh vỡ đại lục của Lôi chi Tiên giới. Khi tiên trận phun cột sáng tiết linh lên trời, tu sĩ trên mảnh vỡ này đều nhìn thấy, tưởng có bảo vật xuất thế và bay tới khu vực trận pháp nhưng bị Vương Lâm chặn ngoài phạm vi nghìn trượng.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0728"]},{"id":"hac-dong-duoi-tran-phap","name":"Hắc động dưới trận pháp","cn":"","capDo":"khac","parentId":"khu-phia-dong-dan-co-phu","blurb":"Lỗ đen lộ ra tại vị trí tiên trận sau khi cột sáng tiết linh tan biến. Từ đây tràn ra dao động tiên lực đủ để tu sĩ ngoài nghìn trượng cảm nhận rõ.","detail":"Khi cột sáng từ tiên trận hoàn toàn tiêu tan, mặt đất tại vị trí trận pháp lộ ra một hắc động. Hắc động này tỏa dao động tiên lực mạnh, cho thấy bên dưới trận có thể là mật thất hoặc không gian ẩn của cửa hàng Tiên nhân trong Dẫn Cơ phủ.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0728"]},{"id":"pham-vi-nghin-truong-quanh-hac-dong","name":"Phạm vi nghìn trượng quanh hắc động","cn":"","aliases":["Nghìn trượng cấm địa","Phạm vi nghìn trượng quanh trận pháp"],"capDo":"khac","parentId":"hac-dong-duoi-tran-phap","blurb":"Vòng ranh giới bụi đất do Vương Lâm lập quanh hắc động trong Lôi chi Tiên giới.","detail":"Đây là phạm vi nghìn trượng quanh hắc động mà Vương Lâm trấn giữ, không cho quần tu tự ý bước vào. Sau khi Đường Ngôn Vân xông vào và bị giết, Vương Lâm tuyên bố kẻ nào tiến vào đều chết, khiến nơi này in sâu trong lòng quần tu như cấm địa tử vong.","theLucLienQuan":["Đường gia"],"nguon":["@c0729"]},{"id":"thong-dao-bi-mat-duoi-hac-dong","name":"Thông đạo bí mật dưới hắc động","cn":"","capDo":"khac","parentId":"hac-dong-duoi-tran-phap","blurb":"Lối đi bí mật do Lý Nguyên phát hiện sau khi đoạt được bảo vật phía dưới hắc động. Điểm đến của thông đạo này chưa được tiết lộ trong chương.","detail":"Thông đạo nằm bên dưới hắc động tại khu vực cấm địa nghìn trượng trong Lôi chi Tiên giới. Lý Nguyên báo cho Vương Lâm rằng ngoài bảo vật đã đoạt được, hắn còn phát hiện lối đi này; cuối chương Vương Lâm cùng Lý Nguyên tiến vào hắc động, còn cửa vào bị cấm chế phong kín.","theLucLienQuan":[],"nguon":["@c0730"]},{"id":"hang-dong-ngam-duoi-cam-che","name":"Hang động ngầm dưới cấm chế","cn":"","capDo":"khac","parentId":"hac-dong-duoi-tran-phap","blurb":"Hang động bên dưới cấm chế nơi Vương Lâm và Lý Nguyên tiến vào sau khi mở lối.","detail":"Bên dưới cấm chế là một hang động nối với thông đạo tối, nơi Lý Nguyên dẫn Vương Lâm đi sâu vào. Trong hang động còn có ba bảo bối kỳ quái mà Lý Nguyên dự định lấy ra để cùng phân tích.","theLucLienQuan":[],"nguon":["@c0731"]},{"id":"thong-dao-hinh-ky-hieu-tien-cam","name":"Thông đạo hình ký hiệu Tiên Cấm","cn":"","capDo":"khac","parentId":"hang-dong-ngam-duoi-cam-che","blurb":"Thông đạo quanh co dưới hang động, toàn bộ đường đi tạo thành một ký hiệu Tiên Cấm.","detail":"Thông đạo không nhánh, càng đi sâu càng gây cảm giác dị thường ở mi tâm. Vương Lâm dùng thần thức phác họa đường đi thành ký hiệu, còn Lý Nguyên nhận ra đó là một loại Tiên Cấm và suy đoán nó thuộc hệ thống đại trận chữa thương chín ký hiệu.","theLucLienQuan":[],"nguon":["@c0731"]},{"id":"con-loc-xoay","name":"Cơn lốc xoáy","cn":"","capDo":"khac","parentId":"hang-dong-ngam-duoi-cam-che","blurb":"Khu vực dẫn tới trận nhãn, bị người bên trong khóa kín và là nơi con mắt bí ẩn xuất hiện.","detail":"Lý Nguyên nhận định cơn lốc xoáy dẫn tới trận nhãn nhưng đã bị người bên trong khóa kín. Trung tâm lốc xoáy hiện ra con mắt truyền âm dụ Vương Lâm đổi tiên cấm lấy tiên thuật, sau đó phóng hồng quang Cực Cảnh truy kích và mê hoặc một tu sĩ vô danh tới gần tự nổ.","theLucLienQuan":[],"nguon":["@c0732"]},{"id":"thong-dao","name":"Thông đạo","cn":"","capDo":"khac","parentId":"hang-dong-ngam-duoi-cam-che","blurb":"Đường nối giữa hang động ngầm và cơn lốc xoáy trong khu vực trận pháp.","detail":"Vương Lâm mang Lý Nguyên rút lui qua thông đạo sau khi nhận ra sự nguy hiểm của cơn lốc xoáy. Hồng quang Cực Cảnh do con mắt phóng ra cũng men theo thông đạo truy kích, xuyên qua lôi quang phòng thủ của Vương Lâm.","theLucLienQuan":[],"nguon":["@c0732"]},{"id":"tang-pham-cac","name":"Tàng Phẩm Các","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mục tiêu mới của Vương Lâm trong Lôi Tiên Giới, được cho là nơi có tiên thuật.","detail":"Tàng Phẩm Các nằm trên một mảnh vỡ bị phong ấn ở vị trí trung tâm phần lớn mảnh vỡ Lôi Tiên Giới. Theo ký ức lão già họ Diêu, nơi này bị phong ấn do tứ đại gia tộc kết hợp tạo thành, cần người am hiểu cấm chế như Lý Nguyên hỗ trợ phá giải.","theLucLienQuan":["Tứ đại gia tộc","Diêu gia"],"nguon":["@c0733"]},{"id":"manh-vo-dai-luc-co-thong-dao-con-loc-xoay","name":"Mảnh vỡ đại lục có thông đạo cơn lốc xoáy","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ đại lục nơi thông đạo và cơn lốc xoáy vừa phát sinh chấn động sau khi phong ấn bị phá thêm.","detail":"Sau biến động trong thông đạo, chấn động từ mảnh vỡ đại lục này lan ra xa. Vương Lâm và Lý Nguyên rời khỏi nơi đó, tiến vào hư vô của Lôi Tiên Giới và đổi hướng tới Tàng Phẩm Các.","theLucLienQuan":[],"nguon":["@c0733"]},{"id":"bon-manh-vo-dai-luc-phat-dao-dong-tien-luc","name":"Bốn mảnh vỡ đại lục phát dao động tiên lực","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Bốn nơi trong Lôi Tiên Giới phát ra dao động tiên lực mạnh, kéo tu sĩ tụ tập.","detail":"Cùng lúc phong ấn trong lốc xoáy biến động, bốn mảnh vỡ đại lục trong Lôi Tiên Giới toát ra dao động tiên lực nồng đậm. Các nơi này đều có phong ấn bảo vệ, cần cấm chế đại sư hoặc nhiều thời gian mới phá được, nên dẫn dụ nhiều tu sĩ và gia tộc kéo tới.","theLucLienQuan":["Các gia tộc tu chân"],"nguon":["@c0733"]},{"id":"manh-vo-dai-luc-man-trai","name":"Mảnh vỡ đại lục mạn trái","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Địa điểm Chiến Không Liệt hẹn Thân Công Hổ gặp để liên thủ đoạt pháp bảo.","detail":"Chiến Không Liệt nói đã hẹn Thân Công Hổ tới mảnh vỡ đại lục mạn trái để liên thủ đoạt lấy pháp bảo. Vương Lâm không đi ngay vì còn việc quan trọng ở Tàng Phẩm Các, chỉ nói nếu rảnh sẽ tới xem.","theLucLienQuan":["La Thiên Tinh Vực"],"nguon":["@c0733"]},{"id":"hoa-tinh-vuc","name":"Hỏa Tinh Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Một tinh vực hoặc khu vực được nhắc trong phần phân hóa cấp bậc các gia tộc tu chân. Nó xuất hiện như bối cảnh so sánh trong hệ thống La Thiên.","detail":"Hỏa Tinh Vực được nêu khi chương giải thích hệ thống gia tộc tu chân và sự phân chia thế lực. Thông tin cụ thể về địa thế chưa được triển khai sâu trong chương này.","theLucLienQuan":[],"nguon":["@c0735"]},{"id":"vien-co-tien-vuc","name":"Viễn Cổ Tiên Vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Địa danh bí ẩn được nhắc khi nói về gia tộc tu chân viễn cổ La Thiên. Gia tộc này có thể biết các bí ẩn liên quan nơi đó.","detail":"Viễn Cổ Tiên Vực được nêu như bí ẩn cực sâu trong thuyết minh về lịch sử La Thiên Tinh Vực. Chương chỉ cho biết gia tộc tu chân viễn cổ có khả năng nắm giữ manh mối về nơi này.","theLucLienQuan":["Gia tộc tu chân viễn cổ La Thiên"],"nguon":["@c0735"]},{"id":"tang-thu-tu-tang-pham-cac","name":"Tầng thứ tư Tàng Phẩm Các","cn":"","capDo":"khac","parentId":"tang-pham-cac","blurb":"Tầng mà Vương Lâm được phán có thể vào theo tư cách Bát Phẩm Thượng Tiên. Người đạt tầng này chọn tiên thuật dựa vào cơ duyên.","detail":"Trong không gian kiểm tra của Tàng Phẩm Các, người sương mù phán Vương Lâm là Bát Phẩm Thượng Tiên và cho phép vào tầng bốn. Cách nói đi kèm là lựa chọn tiên thuật theo cơ duyên, thấp hơn quyền hạn tra cứu ở tầng chín.","theLucLienQuan":["Tàng Phẩm Các"],"nguon":["@c0735"]},{"id":"tang-thu-chin-tang-pham-cac","name":"Tầng thứ chín Tàng Phẩm Các","cn":"","capDo":"khac","parentId":"tang-pham-cac","blurb":"Tầng cao nhất mà Vương Lâm lên được nhờ nữ thi áo trắng đạt tư cách Cửu phẩm tiên quân. Nơi đây có tiên ngọc, bức họa cây và đồng tử cùng câu thơ gợi các thần thông.","detail":"Tầng thứ chín Tàng Phẩm Các là nơi trước đó chưa ai từng tiến vào theo lời ba lão bên ngoài. Vương Lâm lên đến một gian lầu nhỏ, thấy các ô gỗ chứa tiên ngọc và bức họa kèm câu thơ về Hô phong hoán vũ, Tát đậu thành binh, Địa liệt sơn băng, Âm nguyệt hữu tình.","theLucLienQuan":["Tàng Phẩm Các"],"nguon":["@c0735"]},{"id":"khong-gian-ben-trong-buc-hoa","name":"Không gian bên trong bức họa","cn":"","capDo":"khac","parentId":"tang-thu-chin-tang-pham-cac","blurb":"Không gian bên trong bức họa là cảnh giới Vương Lâm nhập vào sau khi thi triển thủ ấn của đồng tử. Nơi này có đại thụ, lá khô, hội chúng mờ ảo, mưa mực và cảnh giảng đạo Hô phong.","detail":"Sau khi Vương Lâm thi triển thủ ấn, nguyên thần hắn bị kéo vào bức tranh và hóa thành đồng tử mặc đạo bào. Trong không gian ấy, câu thơ trên trời hóa thành mưa mực, hư vô hiện ra đông đảo bóng người, rồi người mờ ảo giảng đạo xuất hiện và thi triển Hô phong.","theLucLienQuan":["Tàng Phẩm Các"],"nguon":["@c0736"]},{"id":"dai-mon-loi-tien-gioi","name":"Đại môn Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Địa điểm ở ngoài cực tây Lôi Tiên Giới, nơi tu sĩ phải tới để dùng Lôi Đỉnh trở về. Vương Lâm quyết định hướng tới nơi này sau khi đoạt được Tàng Phẩm Các.","detail":"Đại môn Lôi Tiên Giới được nhắc như vị trí đặc biệt gắn với đường rời khỏi Lôi Tiên Giới. Vương Lâm nhớ lời Thân Công Hổ từng nói: muốn trở về thì phải tới đại môn ở ngoài cực tây rồi dùng Lôi Đỉnh, nên hắn bỏ qua nơi xuất hiện tiên lực dao động và bay về hướng này.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"bon-manh-vo-dai-luc-dong-tay-nam-bac","name":"Bốn mảnh vỡ đại lục đông tây nam bắc","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Bốn mảnh vỡ đại lục ở bốn hướng Lôi Tiên Giới đồng loạt xuất hiện tiên lực dao động và trận pháp cổ xưa. Chúng thu hút nhiều tu sĩ rồi lần lượt biến thành thảm cảnh khi thông đạo sụp đổ.","detail":"Ở bốn hướng đông, tây, nam, bắc của Lôi Tiên Giới, các mảnh vỡ đại lục xuất hiện tiên lực nồng đậm cùng trận pháp cấm chế cổ xưa. Nhiều tu sĩ tụ tập, các cao thủ cấm chế cùng phá giải, nhưng những thông đạo và hang động được mở ra đều kéo theo biến cố chết chóc, cuối cùng bốn thông đạo sụp đổ và tiên lực khổng lồ tràn khắp toàn giới.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"manh-vo-phia-tay","name":"Mảnh vỡ phía tây","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ phía tây Lôi Tiên Giới, nơi Thân Công Hổ và Chiến Không Liệt quan sát trận pháp trên bình nguyên. Sau khi cấm chế bị phá, hang động ngầm hiện ra rồi sụp đổ giết nhiều tu sĩ.","detail":"Tại mảnh vỡ phía tây, bình nguyên có trận pháp cấm chế rộng nghìn trượng tỏa tiên lực nồng đậm. Thân Công Hổ nhận ra nơi này vài tháng trước không hề có cấm chế, còn Chiến Không Liệt cũng nghi việc phá trận quá dễ; tuy vậy nhiều tu sĩ vẫn tiến vào hang động sau trận pháp và bị vùi chết khi thông đạo sụp đổ.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"binh-nguyen-phia-tay","name":"Bình nguyên phía tây","cn":"","capDo":"khac","parentId":"manh-vo-phia-tay","blurb":"Khu bình nguyên trên mảnh vỡ phía tây có trận pháp cấm chế rộng nghìn trượng. Nơi đây tỏa tiên lực nồng đậm và thu hút tu sĩ cùng cao thủ cấm chế tụ tập phá giải.","detail":"Bình nguyên phía tây là nơi Thân Công Hổ từng tới vài tháng trước nhưng khi đó không có cấm chế. Đến chương này, khu vực lại xuất hiện trận pháp cổ xưa, tiên lực dày đặc và bị nhiều tu sĩ vây quanh phá giải, trở thành điểm mở ra hang động ngầm dẫn tới thảm biến phía tây.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"manh-vo-phia-bac","name":"Mảnh vỡ phía bắc","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ đầu tiên trong bốn hướng bị mở cấm chế. Thông đạo gấp khúc phía sau bị hồng quang quét qua rồi sụp đổ, khiến nhiều tu sĩ bỏ mạng.","detail":"Sau khi cấm chế tại mảnh vỡ phía bắc được phá giải, một thông đạo dài gấp khúc hiện ra và các tu sĩ tiến vào. Không lâu sau, hồng quang xuất hiện bên trong, quét qua toàn bộ thông đạo khiến nơi này sụp đổ, tiêu tan cùng phần lớn tu sĩ bên trong.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"manh-vo-phia-dong","name":"Mảnh vỡ phía đông","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ phía đông có cấm chế được mở sau phía bắc. Tu sĩ tiến vào thông đạo tại đây gặp lốc xoáy ngũ sắc rồi tự nổ quỷ dị.","detail":"Khi cấm chế tại mảnh vỡ phía đông được phá giải, các tu sĩ nối nhau tiến vào thông đạo. Bên trong, họ nhìn thấy lốc xoáy ngũ sắc và từ người đầu tiên đến người cuối cùng đều tự nổ một cách quỷ dị, để hồng quang lan khắp thông đạo.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"manh-vo-phia-nam","name":"Mảnh vỡ phía nam","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Một trong bốn mảnh vỡ có trận pháp cổ xưa bị phá giải. Sau biến cố phía bắc và phía đông, thảm kịch tương tự tiếp tục xảy ra tại nơi này.","detail":"Mảnh vỡ phía nam cũng thuộc bốn nơi xuất hiện tiên lực dao động và trận pháp cấm chế cổ xưa. Khi biến cố lan tới đây, thảm cảnh tương tự những thông đạo khác tái diễn, góp phần khiến Lôi Tiên Giới chìm trong cảnh chết chóc và hỗn loạn.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"chin-manh-vo-co-dau-an","name":"Chín mảnh vỡ có dấu ấn","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Chín vị trí trong Lôi Tiên Giới đồng thời hiện dấu ấn trận pháp đỏ. Chúng liên quan trực tiếp tới việc mở phong ấn cánh tay cụt.","detail":"Sau khi bốn thông đạo sụp đổ và tiên lực bùng phát, trong toàn bộ Lôi Tiên Giới có chín mảnh vỡ đại lục chấn động dữ dội. Mặt đất trên các mảnh vỡ này hiện những dấu ấn trận pháp khác nhau, phát hồng quang khiến tu sĩ sợ hãi; một trong số đó bị khí tức từ cánh tay cụt phá tan từ bên trong.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"trung-tam-loi-tien-gioi","name":"Trung tâm Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Đích đến của cánh tay cụt sau khi thoát khỏi phong ấn. Vị trí này trở thành điểm hướng tới của biến cố lớn trong Lôi Tiên Giới.","detail":"Khi cánh tay cụt bị phong ấn vô số năm phá tan mảnh vỡ đại lục và thoát ra, nó không dừng lại ở nơi phong ấn mà bay thẳng về trung tâm Lôi Tiên Giới. Điều này cho thấy trung tâm Lôi Tiên Giới có liên hệ sâu với biến cố phong ấn vừa thức tỉnh.","theLucLienQuan":[],"nguon":["@c0738"]},{"id":"cuc-tay-loi-tien-gioi","name":"Cực tây Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Cực tây Lôi Tiên Giới là phương hướng Vương Lâm và Lý Nguyên lao tới trước khi gặp cánh tay cụt đỏ. Đây cũng là hướng liên quan tới cửa lớn Tiên Giới, lối thoát của các tu sĩ.","detail":"Trong chương này, Vương Lâm và Lý Nguyên đang lao về cực tây thì gặp hồng quang chứa cánh tay cụt đỏ. Cuộc chạm trán ở hướng này khiến Vương Lâm nhận ra Lôi Tiên Giới sắp đại loạn và phải nhanh chóng chạy về cửa Tiên Giới.","theLucLienQuan":["Tu sĩ Lôi Tiên Giới"],"nguon":["@c0739"]},{"id":"phong-an-thu-chin","name":"Phong ấn thứ chín","cn":"","capDo":"khac","parentId":"manh-vo-dai-luc-co-thong-dao-con-loc-xoay","blurb":"Phong ấn thứ chín là vị trí giam giữ mắt phải chứa Cực Cảnh của quái nhân tóc bạc. Quái nhân phá nơi này để lấy lại mắt phải sau khi tái hợp thân thể.","detail":"Sau khi phục sinh, quái nhân tóc bạc tới mảnh vỡ đại lục từng có thông đạo và phá hủy phong ấn thứ chín. Bên trong phong ấn này là con mắt phải của hắn, nơi hắn nói Cực Cảnh năm đó bị phong ấn.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0739"]},{"id":"khoang-cach-nam-muoi-truong-truoc-dai-mon","name":"Khoảng cách năm mươi trượng trước đại môn","cn":"","capDo":"khac","parentId":"dai-mon-loi-tien-gioi","blurb":"Vị trí sát đại môn Tiên giới nơi Vương Lâm bị quái nhân tóc bạc ép hiện thân. Từ đây hắn lập tức đẩy Lý Nguyên về phía cửa.","detail":"Khi Vương Lâm dùng đạo dung thiên địa đưa Lý Nguyên tiếp cận đại môn, quái nhân tóc bạc xé tìm trong thiên địa và ép hai người lộ ra ở nơi cách đại môn hơn năm mươi trượng. Đây là khoảng cách quyết định để Lý Nguyên kịp dùng Lôi Đỉnh rời đi, còn Vương Lâm bị kẹt lại khi cửa tiêu tan.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0740"]},{"id":"chien-truong-trong-pham-vi-muoi-dam","name":"Chiến trường trong phạm vi mười dặm","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Khu vực giao chiến được lão giả trong thân thể Vương Lâm tạm thời dọn trống bằng tử quang.","detail":"Sau khi lão giả trong thân thể Vương Lâm khiến tử quang tán thành gợn sóng, tu sĩ trong phạm vi mười dặm đều bị đẩy lui, để lại khoảng trống chỉ còn Vương Lâm và thanh niên tà khí đối diện nhau.","theLucLienQuan":[],"nguon":["@c0743"]},{"id":"vo-so-manh-dai-luc","name":"Vô số mảnh đại lục","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Nhiều mảnh đại lục được Vương Lâm và thanh niên tà khí vượt qua trong cuộc truy đuổi cuối chương.","detail":"Ở cuối chương 743, lão giả điều khiển thân thể Vương Lâm và thanh niên tà khí cùng dung nhập thiên địa, nhanh chóng vượt qua nhiều mảnh đại lục trong Lôi chi Tiên giới khi hướng tới nơi bản thể của lão giả.","theLucLienQuan":[],"nguon":["@c0743"]},{"id":"cho-ban-the-cua-lao-gia-than-bi","name":"Chỗ bản thể của lão giả thần bí","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Đích đến mà lão giả muốn dẫn thanh niên tà khí tới, nơi được nói có vô số luyện khí sĩ.","detail":"Thanh niên tà khí nói hắn đã nhìn ra mục đích của lão giả là dụ mình tới chỗ bản thể của lão. Hắn vẫn thuận theo vì muốn thôn phệ bản thể ấy và vô số luyện khí sĩ ở đó để khôi phục tu vi.","theLucLienQuan":[],"nguon":["@c0743"]},{"id":"trieu-tien-dai","name":"Triều Tiên Đài","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Triều Tiên Đài là đại lục ở phương bắc Lôi tiên giới, từng là trung tâm của Lôi tiên giới năm xưa.","detail":"Thanh niên đầy tà khí nhận ra nơi này là Triều Tiên Đài của Lôi tiên giới, đồng thời là vùng đất gần viễn cổ tiên vực nhất trước khi tiên vực ấy biến mất. Khi viễn cổ tiên vực còn tồn tại, tiên nhân viễn cổ hạ giới đặt bước đầu tiên tại nơi này.","theLucLienQuan":["Lôi tiên giới","Viễn cổ tiên vực"],"nguon":["@c0744"]},{"id":"phuong-bac-loi-tien-gioi","name":"Phương bắc Lôi tiên giới","cn":"","capDo":"vuc","parentId":"loi-tien-gioi","blurb":"Phương bắc Lôi tiên giới là khu vực nơi Vương Lâm hiện thân sau khi bị lão giả thần bí điều khiển thân thể di chuyển bằng dung nhập thiên địa.","detail":"Tại khu vực phương bắc này, nguyên thần lão giả thần bí trong thân thể Vương Lâm hoàn toàn tiêu tán. Ngay sau đó, thanh niên đầy tà khí truy tới và cuộc giao chiến tiếp tục diễn ra trên đại lục Triều Tiên Đài.","theLucLienQuan":["Lôi tiên giới"],"nguon":["@c0744"]},{"id":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","name":"Bốn mươi chín mảnh vỡ đại lục của Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Bốn mươi chín mảnh vỡ đại lục được Viêm Lôi Tử dùng làm nền cho Lôi Tiên Đại Trận. Chúng bị Lôi Thú kéo lên, xoay quanh trung tâm thành thế trận hoa mai và tiếp nhận pháp linh để luyện hóa.","detail":"Trong chương 745, toàn bộ bốn mươi chín mảnh vỡ đại lục cùng chấn động, xích nối tan vỡ và các mảnh vận chuyển quanh mảnh vỡ trung tâm. Khi Viêm Lôi Tử gọi nguyên thần từ mảnh kính cũ, từng mảnh vỡ được đưa pháp linh vào để tăng linh tính và trở thành bộ phận của pháp bảo đang hình thành.","theLucLienQuan":["Lôi chi Tiên giới","La Thiên Tinh Vực"],"nguon":["@c0745"]},{"id":"manh-vo-dai-luc-trung-tam","name":"Mảnh vỡ đại lục trung tâm","cn":"","capDo":"khac","parentId":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","blurb":"Mảnh vỡ nơi Vương Lâm và thanh niên đầy tà khí đang đứng khi đại trận phát động. Nó được lấy làm trung tâm để các mảnh vỡ khác xoay quanh tạo hình hoa mai.","detail":"Khi bốn mươi chín mảnh vỡ đại lục của Lôi Tiên Giới vận chuyển, mảnh vỡ chỗ Vương Lâm và thanh niên đầy tà khí được đặt ở vị trí trung tâm. Từ vị trí này, các mảnh vỡ còn lại xoay chuyển, tạo thành đại trận tuyệt luân và kéo theo biến cố sụp đổ toàn giới.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0745"]},{"id":"vach-ngan-khong-gian","name":"Vách ngăn không gian","cn":"","capDo":"khac","parentId":null,"blurb":"Ranh giới không gian mà Viêm Lôi Tử muốn mở bằng pháp bảo luyện từ Lôi Tiên Giới. Nếu mở được, tu sĩ La Thiên Tinh Vực có thể tiến vào Liên Minh Tinh Vực mà không cần La Thiên Thạch.","detail":"Viêm Lôi Tử xem pháp bảo luyện từ một nửa Lôi Tiên Giới là công cụ để mở vách ngăn không gian giữa La Thiên Tinh Vực và Liên Minh Tinh Vực. Mục tiêu này gắn trực tiếp với dã tâm chiến tranh của hắn đối với Liên Minh Tinh Vực.","theLucLienQuan":["La Thiên Tinh Vực","Liên Minh Tinh Vực"],"nguon":["@c0745"]},{"id":"hu-khong-loi-tien-gioi","name":"Hư không Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Vùng hư không trong Lôi Tiên Giới xuất hiện nhiều vết nứt khi đại trận vận chuyển. Gió lạnh và khí tức hủy diệt tràn ra, báo hiệu toàn giới sụp đổ lần thứ hai trên phạm vi lớn.","detail":"Khi bốn mươi chín mảnh vỡ đại lục xoay chuyển, lốc xoáy và lực hút kéo theo sự nứt rách của hư không Lôi Tiên Giới. Các khe nứt đáng sợ mở ra, khí tức hủy diệt lan tràn khiến tu sĩ trong giới kinh hoàng.","theLucLienQuan":["Lôi chi Tiên giới"],"nguon":["@c0745"]},{"id":"manh-vo-dai-luc-thu-bay","name":"Mảnh vỡ đại lục thứ bảy","cn":"","capDo":"khac","parentId":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","blurb":"Một mảnh vỡ trong Tiên Giới Đại Trận, nơi nguyên thần Khuy Niết tu sĩ quy vị. Khi nguyên thần nhập vào, uy áp và linh tính của đại trận tăng mạnh.","detail":"Mảnh vỡ đại lục thứ bảy là vị trí Viêm Lôi Tử đưa nguyên thần Khuy Niết tu sĩ tam phẩm thiên tiên vào trong quá trình hoàn thiện Tiên Giới Đại Trận. Đây là một trong các điểm trận của bốn mươi chín mảnh vỡ đại lục.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0746"]},{"id":"manh-vo-dai-luc-thu-sau","name":"Mảnh vỡ đại lục thứ sáu","cn":"","capDo":"khac","parentId":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","blurb":"Một điểm trận của Tiên Giới Đại Trận, nơi cửu phẩm thiên tiên sát khí quy vị làm đệ lục thần. Sau khi nhập trận, sát khí bao bọc mạnh hơn quanh trận pháp.","detail":"Mảnh vỡ đại lục thứ sáu tiếp nhận nguyên thần người đàn ông trung niên sát khí, được Viêm Lôi Tử gọi là đệ lục thần. Vị trí này góp phần làm sát khí của toàn bộ đại trận trở nên rõ rệt.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0746"]},{"id":"manh-vo-dai-luc-thu-nam","name":"Mảnh vỡ đại lục thứ năm","cn":"","capDo":"khac","parentId":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","blurb":"Mảnh vỡ nơi lão già nhị phẩm tiên vương nhập trận. Uy áp từ nguyên thần tiên vương khiến khí tức của đại trận tiếp tục tăng lên.","detail":"Mảnh vỡ đại lục thứ năm được dùng để chứa nguyên thần lão già nhị phẩm tiên vương. Trước khi dung nhập, lão còn tỉnh táo nhắc Viêm Lôi Tử nhớ lời hứa, khiến vị trí này gắn với một ràng buộc chưa rõ giữa hai bên.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0746"]},{"id":"manh-vo-trung-tam","name":"Mảnh vỡ trung tâm","cn":"","aliases":["Mảnh vỡ thứ nhất"],"capDo":"khac","parentId":"bon-muoi-chin-manh-vo-dai-luc-cua-loi-tien-gioi","blurb":"Vị trí trung tâm của Tiên Giới Đại Trận, nơi Sát Lục Tiên Quân lục phẩm quy vị làm đệ nhất thần. Sau khi hắn nhập vào, sát khí bao phủ toàn bộ các mảnh vỡ đại lục.","detail":"Mảnh vỡ trung tâm là điểm then chốt của bốn mươi chín mảnh vỡ đại lục, được Viêm Lôi Tử dành cho đệ nhất thần. Khi Sát Lục Tiên Quân dung nhập, sát khí lan khắp trận, đánh dấu bước hoàn thiện quan trọng của Tiên Giới Đại Trận.","theLucLienQuan":["Lôi Tiên Giới","Vũ Tiên Giới"],"nguon":["@c0746"]},{"id":"thanh-thuy-quoc-dia-danh","name":"Thanh Thủy Quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia trong thượng cổ tu chân giới, nơi Thanh Thủy từng là thái tử trước khi phi thăng. Địa danh này được Viêm Lôi Tử nêu khi kể lai lịch Thanh Thủy.","detail":"Thanh Thủy Quốc thuộc bối cảnh thượng cổ tu chân giới. Theo lời Viêm Lôi Tử, Thanh Thủy xuất thân là thái tử của quốc gia này, sau đó phi thăng đến Lôi Tiên Giới và trở thành Tiên Quân.","theLucLienQuan":["Thanh Thủy Quốc"],"nguon":["@c0746"]},{"id":"thuong-co-tu-chan-gioi","name":"Thượng cổ tu chân giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bối cảnh thời đại và địa vực nơi Thanh Thủy Quốc tồn tại. Viêm Lôi Tử nhắc đến nơi này khi truy nguyên thân phận Thanh Thủy.","detail":"Thượng cổ tu chân giới là nền cảnh trước khi Thanh Thủy phi thăng tiên giới. Thanh Thủy Quốc nằm trong địa vực này, và Thanh Thủy từng là thái tử ở đó trước khi đến Lôi Tiên Giới.","theLucLienQuan":["Thanh Thủy Quốc"],"nguon":["@c0746"]},{"id":"dien-tien-gioi","name":"Điện Tiên Giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Một tiên giới được nêu trong lời đề nghị truy tìm nguyên nhân biến cố của Viêm Lôi Tử.","detail":"Điện Tiên Giới xuất hiện trong lời Viêm Lôi Tử khi ông muốn cùng Thanh Thủy tìm đáp án về biến cố tiên giới và tình trạng Tiên Quân mất thần trí.","theLucLienQuan":["Điện Tiên Giới"],"nguon":["@c0747"]},{"id":"truyen-tong-tran-cua-loi-tien-dien","name":"Truyền tống trận của Lôi Tiên Điện","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Truyền tống trận của Lôi Tiên Điện là điểm đến của Chiến Không Liệt trong lúc Lôi Tiên Giới sụp đổ.","detail":"Chiến Không Liệt biết vị trí truyền tống trận nhờ thân phận tân sứ giả Lôi Tiên Điện. Hắn cấp tốc bay về nơi này và suy đoán các sứ giả Lôi Tiên Điện khác cũng có thể đã tập trung tại đó.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0749"]},{"id":"khe-khong-gian","name":"Khe không gian","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Khe không gian là những vết nứt nguy hiểm rải khắp Lôi Tiên Giới. Mảnh nhỏ trăm trượng của Vương Lâm men qua chúng để mở sinh lộ cho nhiều tu sĩ.","detail":"Trong hành trình lao ra khỏi Lôi Tiên Giới, các khe không gian là hiểm họa liên tục làm tảng đá ngàn trượng của nhóm Dương Thực vỡ vụn. Cuối chương, văn sĩ áo lam bị Hô Phong ép lùi vào một khe không gian dài hơn ba trượng và biến mất.","theLucLienQuan":[],"nguon":["@c0750"]},{"id":"man-sang-ngan-truong","name":"Màn sáng ngàn trượng","cn":"","capDo":"khac","parentId":"manh-dai-luc-chua-truyen-tong-tran","blurb":"Màn sáng khoảng ngàn trượng bao quanh mảnh đại lục chứa truyền tống trận của Lôi Tiên Điện.","detail":"Màn sáng bao quanh mảnh đại lục có truyền tống trận, được nguyên lực gia cố và tạo hào khe nứt ngoài rìa để ngăn người vượt qua; về sau bị mảnh nhỏ trăm trượng cùng hợp lực tu sĩ đánh sập, tan thành từng mảnh.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0751"]},{"id":"manh-dai-luc-chua-truyen-tong-tran","name":"Mảnh đại lục chứa truyền tống trận","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh đại lục nằm trong màn sáng ngàn trượng, nơi có trận pháp truyền tống của Lôi Tiên Điện.","detail":"Mảnh đại lục nằm bên trong màn sáng khoảng ngàn trượng, chứa trận pháp truyền tống của Lôi Tiên Điện; trở thành mục tiêu xông vào của Vương Lâm cùng cả ngàn tu sĩ khi Lôi Tiên Giới sụp đổ, được xem như đường sống duy nhất.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0751"]},{"id":"manh-nho-tram-truong-dia-diem","name":"Mảnh nhỏ trăm trượng","cn":"","capDo":"khac","parentId":"loi-chi-tien-gioi","blurb":"Mảnh vỡ đi trước dẫn đường, tạo hy vọng sinh tồn cho đám tu sĩ trong Lôi Tiên Giới. Trên đó có Vương Lâm và hai tu sĩ Dương Thực từng ẩn giấu tu vi.","detail":"Mảnh nhỏ trăm trượng là nơi các tu sĩ bám theo để tìm đường sống sau biến cố màn sáng tan nát. Trong chương này, việc nam tử trung niên gầy gò bộc lộ tu vi Dương Thực cho thấy trên mảnh nhỏ từng có những tu sĩ mạnh ẩn giấu rất sâu.","theLucLienQuan":[],"nguon":["@c0752"]},{"id":"loi-quang-thiet-lien","name":"Lôi quang thiết liên","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Dây xích ánh lôi trong Lôi Tiên Giới cũng bị băng đen lan phủ sau biến cố sụp đổ. Nó được nhắc như một phần của cảnh giới bị đóng băng toàn diện.","detail":"Sau khi cột sáng biến mất và gió lạnh từ khe nứt tràn ra, các mảnh đại lục còn sót trong Lôi Tiên Giới bị băng đen đóng kín. Lôi quang thiết liên nằm gần các mảnh đại lục cũng bị hàn băng lan tới, cuối cùng chìm trong trạng thái đóng băng cùng thế giới đổ nát.","theLucLienQuan":["Lôi Tiên Giới"],"nguon":["@c0754"]},{"id":"tinh-vuc-la-thien","name":"Tinh vực La Thiên","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực nơi tin tức Lôi Tiên Giới sụp đổ và danh tiếng Hứa Mộc lan truyền sau khi hơn trăm tu sĩ sống sót trở về. Đây cũng là khu vực chứa đại lục thứ tư và vùng ranh giới phía Tây.","detail":"Sau biến cố Lôi Tiên Giới, hơn trăm tu sĩ được truyền tống về đại lục thứ tư của tinh vực La Thiên. Từ các gia tộc của họ, chuyện Hứa Mộc kháng quái nhân tóc bạc, cứu người và dẫn mọi người qua truyền tống trận của Lôi Tiên điện nhanh chóng lan ra khắp La Thiên.","theLucLienQuan":["Lôi Tiên điện","Hơn mười gia tộc tu chân La Thiên"],"nguon":["@c0754"]},{"id":"dai-luc-thu-tu-la-thien","name":"Đại lục thứ tư La Thiên","cn":"","capDo":"khac","parentId":"tinh-vuc-la-thien","blurb":"Nơi một trăm dao động truyền tống đồng thời xuất hiện, đưa các tu sĩ sống sót từ Lôi Tiên Giới trở về. Từ đây tin tức thảm họa và danh tiếng Hứa Mộc lan rộng.","detail":"Trên đại lục thứ tư La Thiên, khoảng một trăm vị trí xuất hiện dao động không khí gần như cùng lúc, mỗi nơi hiện ra một tu sĩ sống sót khỏi Lôi Tiên Giới. Sau khi xác định phương hướng, họ trở về gia tộc, kéo theo việc các gia tộc liên hợp và cùng truyền bá tên Hứa Mộc.","theLucLienQuan":["Hơn mười gia tộc tu chân La Thiên","Các gia tộc lớn nhỏ của đại lục thứ tư La Thiên"],"nguon":["@c0754"]},{"id":"khu-vuc-phia-tay-tinh-vuc-la-thien","name":"Khu vực phía Tây tinh vực La Thiên","cn":"","capDo":"vuc","parentId":"tinh-vuc-la-thien","blurb":"Một trong bốn vùng Đông Tây Nam Bắc của tinh vực La Thiên, nổi bật bởi nhiều tinh vân và mãnh thú. Nơi này ít tu sĩ hơn trước và có nhiều vùng nguy hiểm khó đặt chân vào.","detail":"Khu vực phía Tây La Thiên được miêu tả rộng lớn, nhiều tinh vân và có mãnh thú nhiều nhất trong bốn phương. Theo thời gian, tu sĩ ở đây thưa dần, nhiều vị trí nguy hiểm đến mức tu sĩ bình thường không thể tiến vào, tạo nên vùng ranh giới đáng sợ ở sâu bên trong.","theLucLienQuan":["La Thiên"],"nguon":["@c0754"]},{"id":"duong-bien-gioi-vung-ranh-gioi-phia-tay-la-thien","name":"Đường biên giới/vùng ranh giới phía Tây La Thiên","cn":"","aliases":["Đường biên giới","Vùng ranh giới phía Tây La Thiên"],"capDo":"vuc","parentId":"khu-vuc-phia-tay-tinh-vuc-la-thien","blurb":"Khu vực nguy hiểm ở phía Tây La Thiên, nơi có mãnh thú và những vị trí kinh khủng mà chỉ người có đại thần thông mới dám vào ngoài rìa. Vương Lâm bị truyền tống tới sâu trong trung tâm vùng này.","detail":"Vùng ranh giới phía Tây La Thiên là nơi tu sĩ hiếm khi đặt chân sâu vào, bởi bên trong có mãnh thú và các khu vực nguy hiểm khó lường. Sau khi rời Lôi Tiên Giới, Vương Lâm xuất hiện tại sâu trung tâm nơi này, giữa bóng tối và sương mù dày đặc.","theLucLienQuan":["La Thiên"],"nguon":["@c0754"]},{"id":"trung-tam-vung-ranh-gioi","name":"Trung tâm vùng ranh giới","cn":"","capDo":"khac","parentId":"duong-bien-gioi-vung-ranh-gioi-phia-tay-la-thien","blurb":"Nơi sâu trong vùng ranh giới phía Tây La Thiên, tối đen không ánh sáng và phủ sương mù kỳ dị. Vương Lâm dùng lôi cầu mở đường rồi dung nhập không gian để vượt qua.","detail":"Trung tâm vùng ranh giới chìm trong bóng tối và sương mù dày đặc, thứ sương mù có vẻ sợ ánh sáng lôi cầu nhưng lại khiến Vương Lâm cảm thấy nguy hiểm như ẩn chứa sinh mạng. Hắn phi hành ba ngày vẫn không rời khỏi, sau đó dung nhập không gian để xuyên qua và đến khu vực sương mù mỏng hơn.","theLucLienQuan":[],"nguon":["@c0754"]},{"id":"buc-tuong-thit-do-sam","name":"Bức tường thịt đỏ sậm","cn":"","capDo":"khac","parentId":"trung-tam-vung-ranh-gioi","blurb":"Vật thể khổng lồ ở cuối làn sương trong trung tâm vùng ranh giới. Nó cách Vương Lâm ba trượng, kéo dài không thấy điểm cuối và khi ngẩng đầu cũng chỉ thấy toàn thịt.","detail":"Sau khi Vương Lâm dung nhập không gian và xuất hiện tại nơi sương mù mỏng hơn, trước mặt hắn chỉ ba trượng là một bức tường thịt đỏ sậm khổng lồ. Bức tường này kéo dài vô tận, nhìn sang hai bên không thấy điểm cuối, ngẩng lên cũng chỉ thấy thịt, khiến hắn biến sắc.","theLucLienQuan":[],"nguon":["@c0754"]},{"id":"buc-tuong-thit-khong-lo","name":"Bức tường thịt khổng lồ","cn":"","capDo":"khac","parentId":null,"blurb":"Vật thể khổng lồ như bức tường sống, không đứng yên mà nhúc nhích, có khe hở phun sương đen. Nó chặn trạng thái dung hợp với trời đất của Vương Lâm và dẫn tới lối vào khu vực đại lục lơ lửng.","detail":"Khi Vương Lâm dung hợp với trời đất để hướng tới tinh cầu tu chân của mình, hắn bị cảm giác va phải tường làm lệch điểm đến. Trước mắt hắn sau đó là bức tường thịt khổng lồ đang nhúc nhích; vô số khe hở trên bề mặt phun ra sương đen rồi dần khép lại, một trong các khe hở trở thành lối đi để hắn tiến vào khu vực Tiên Di tộc.","theLucLienQuan":["Tiên Di tộc"],"nguon":["@c0755"]},{"id":"dai-luc-lo-lung-giua-khong-trung","name":"Đại lục lơ lửng giữa không trung","cn":"","capDo":"khac","parentId":null,"blurb":"Đại lục rộng lớn lơ lửng trong vùng có các điểm sáng trên bầu trời. Đây là nơi Vương Lâm gặp người Tiên Di tộc và được lão nhân tóc bạc mời tiến vào.","detail":"Sau khi vượt qua con đường hẹp trong bức tường thịt, Vương Lâm vọt ra khỏi miệng đường hầm và nhìn thấy một đại lục khổng lồ lơ lửng phía trước. Từ nơi này có hơn trăm đạo cầu vồng của người Tiên Di tộc lao tới, mở ra cuộc tiếp xúc giữa Vương Lâm và tộc này.","theLucLienQuan":["Tiên Di tộc"],"nguon":["@c0755"]},{"id":"con-duong-hep-trong-buc-tuong-thit","name":"Con đường hẹp trong bức tường thịt","cn":"","capDo":"khac","parentId":"buc-tuong-thit-khong-lo","blurb":"Lối đi nằm sau khe hở trên bức tường thịt khổng lồ. Sau khi Vương Lâm lao vào, phía sau liên tục khép lại như truy đuổi, cuối cùng dẫn hắn ra vùng đại lục lơ lửng.","detail":"Khi các khe hở trên bức tường thịt dần thu nhỏ, Vương Lâm chọn lao vào một khe hở để tìm lối ra. Bên trong là con đường hẹp, phía sau khép lại không ngừng, buộc hắn tăng tốc cho tới khi vọt khỏi miệng đường hầm và thấy đại lục lơ lửng giữa không trung.","theLucLienQuan":["Tiên Di tộc"],"nguon":["@c0755"]},{"id":"binh-nguyen-cua-toc-tien-di-tien-tuyen","name":"Bình nguyên của tộc Tiên Di/Tiên Tuyển","cn":"","capDo":"khac","parentId":"dai-luc-lo-lung-giua-khong-trung","blurb":"Vùng bình nguyên rộng lớn, màu mỡ, có gió nhẹ và mùi cỏ thơm, dẫn tới nơi cư trú của bộ tộc.","detail":"Vương Lâm theo lão nhân tới gần đại lục và nhìn thấy bình nguyên rộng lớn ở phía trước. Đây là khu vực bao quanh trung tâm cư trú của tộc Tiên Di/Tiên Tuyển.","theLucLienQuan":["Tộc Tiên Di / Tộc Tiên Tuyển"],"nguon":["@c0756"]},{"id":"khu-kien-truc-co-xua-cua-toc-tien-di-tien-tuyen","name":"Khu kiến trúc cổ xưa của tộc Tiên Di/Tiên Tuyển","cn":"","capDo":"khac","parentId":"binh-nguyen-cua-toc-tien-di-tien-tuyen","blurb":"Quần thể kiến trúc cổ nằm giữa bình nguyên, còn nguyên nhưng phủ dấu vết thời gian.","detail":"Nơi đông đảo tộc nhân Tiên Di/Tiên Tuyển sinh sống. Bên ngoài khu kiến trúc có cấm chế khổng lồ do tiên vương bày ra để bảo hộ bộ tộc khỏi Vụ thú.","theLucLienQuan":["Tộc Tiên Di / Tộc Tiên Tuyển"],"nguon":["@c0756"]},{"id":"cam-dia-cua-toc-tien-di-tien-tuyen","name":"Cấm địa của tộc Tiên Di/Tiên Tuyển","cn":"","capDo":"khac","parentId":"khu-kien-truc-co-xua-cua-toc-tien-di-tien-tuyen","blurb":"Nơi đặt Huyền Âm đỉnh mà tộc Tiên Di/Tiên Tuyển đời đời bảo vệ.","detail":"Sau khi nghe lão nhân kể về tai họa Huyền Âm đỉnh, Vương Lâm hỏi vị trí của đỉnh và muốn tới cấm địa tận mắt xem vật này. Tháp Sơn xuất hiện ngăn cản việc đưa người ngoài tới nơi đó.","theLucLienQuan":["Tộc Tiên Di / Tộc Tiên Tuyển"],"nguon":["@c0756"]},{"id":"manh-dat-yeu-linh","name":"Mảnh đất yêu linh","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm Vương Lâm từng biết, được nhắc lại khi hắn so sánh linh giáp của Tháp Sơn với áo giáp Tán Ma.","detail":"Khi nhìn thấy linh giáp do tiên ban thưởng trên người Tháp Sơn, Vương Lâm liên hệ nó với áo giáp Tán Ma từng thấy ở mảnh đất yêu linh, chỉ khác ở chỗ ma khí của linh giáp bị áp chế nhiều hơn.","theLucLienQuan":["Tán Ma"],"nguon":["@c0757"]},{"id":"huyen-am-dinh-dia-danh","name":"Huyền Âm đỉnh","cn":"","capDo":"khac","parentId":"manh-dat-yeu-linh","blurb":"Địa điểm Vương Lâm yêu cầu được đưa tới, lối vào nằm dưới một tế đàn có cửa tím.","detail":"Huyền Âm đỉnh được tiếp cận qua cánh cửa lớn màu tím dưới tế đàn. Bên trong cửa tối om, tỏa gió lạnh, có nhiều khí lạnh và được thần thức Vương Lâm cảm nhận là ẩn giấu tiên khí.","theLucLienQuan":["Tiên Di tộc"],"nguon":["@c0758"]},{"id":"te-dan-cua-tim-huyen-am-dinh","name":"Tế đàn cửa tím Huyền Âm đỉnh","cn":"","capDo":"khac","parentId":"huyen-am-dinh-dia-danh","blurb":"Tế đàn nhiều vết nứt, bên dưới có cửa tím dẫn vào Huyền Âm đỉnh.","detail":"Tế đàn có kích thước bình thường, nhiều vết nứt; phía dưới là cánh cửa lớn màu tím khắc ký hiệu lấp lánh. Lão nhân dùng máu vẽ ký hiệu trong hư không để mở cửa, còn Tháp Sơn nói mình cả đời bảo vệ tế đàn này và xin tự dẫn Vương Lâm vào.","theLucLienQuan":["Tiên Di tộc"],"nguon":["@c0758"]},{"id":"the-gioi-u-minh-thu","name":"Thế giới U Minh thú","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian nơi tộc Tiên Tuyển sinh sống và canh giữ Huyền Âm đỉnh. Theo điển tịch của tộc, Tiêu Dao tiên vương đã đưa họ vào đây để đời đời bảo vệ đỉnh.","detail":"Thế giới U Minh thú là vùng bị phong ấn, khiến Tháp Sơn và tộc Tiên Tuyển không thể rời khỏi. Tháp Sơn từng thử vượt qua tường thịt để tìm tiên nhân nhưng thất bại, còn điển tịch trong tộc nói Tiêu Dao tiên vương đưa họ vào đây để canh giữ Huyền Âm đỉnh cho tới ngày ông trở lại.","theLucLienQuan":["Tộc Tiên Tuyển","Tiêu Dao tiên vương"],"nguon":["@c0759"]},{"id":"day-cua-vao-huyen-am-dinh","name":"Đáy cửa vào Huyền Âm đỉnh","cn":"","capDo":"khac","parentId":"the-gioi-u-minh-thu","blurb":"Không gian rộng khoảng trăm trượng ở cuối nhiều nhịp cầu thang lạnh dày. Chính giữa nơi này đặt Huyền Âm đỉnh và chín sọ người xếp thành bố cục trận pháp.","detail":"Đáy cửa vào Huyền Âm đỉnh là nơi Tháp Sơn dẫn Vương Lâm tới sau khi đi qua nhiều tầng cầu thang. Khí lạnh ở đây rất dày, chính giữa có đại đỉnh khoảng mười trượng, miệng đỉnh tràn hắc khí bị phong ấn và xung quanh đặt chín sọ người có ký hiệu ở mi tâm.","theLucLienQuan":["Tộc Tiên Tuyển"],"nguon":["@c0759"]},{"id":"canh-cua-ben-ngoai-huyen-am-dinh","name":"Cánh cửa bên ngoài Huyền Âm đỉnh","cn":"","capDo":"khac","parentId":"day-cua-vao-huyen-am-dinh","blurb":"Lối ra bên ngoài khu vực Huyền Âm đỉnh. Vương Lâm rút lui qua đây cùng Tháp Sơn khi ảo ảnh nữ nhân hắc khí truy kích.","detail":"Cánh cửa bên ngoài Huyền Âm đỉnh là điểm lão nhân Tiên Tuyển đứng chờ. Khi hắc khí đuổi tới, lão dùng ký hiệu từ cây thực vật ở mi tâm in lên cửa để khiến cánh cửa khép lại, tạm chặn đường truy kích của ảo ảnh nữ nhân.","theLucLienQuan":["Tộc Tiên Tuyển"],"nguon":["@c0759"]},{"id":"noi-bi-phong-an-co-buc-tuong-thit","name":"Nơi bị phong ấn có bức tường thịt","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực Vương Lâm đang ở sau khi truyền tống, có bầu trời lam nhưng tận cùng đám mây vẫn là bức tường thịt.","detail":"Vương Lâm nhận định nơi này bị phong ấn nhưng vẫn có thể truyền tống tới được. Dù nguy hiểm, hắn xem đây là chỗ ẩn thân tốt, đồng thời quan sát bầu trời lam và bức tường thịt ở tận cùng đám mây trong lúc suy tính đường lui.","theLucLienQuan":["Tộc Tiên Tuyển","Tộc Tiên Di"],"nguon":["@c0760"]},{"id":"vach-tuong-anh-sang-mau-lam","name":"Vách tường ánh sáng màu lam","cn":"","capDo":"khac","parentId":"dai-luc-lo-lung-giua-khong-trung","blurb":"Ranh giới vô biên bao quanh đại lục của Tiên Tuyển Tộc. Nó khiến không gian trông như ngoại giới nhưng thực chất bị phong kín.","detail":"Sau mười ngày ở lại Tiên Tuyển Tộc, Vương Lâm dò xét chân trời và bốn phía đại lục nhưng chỉ thấy vách tường vô biên ngăn cách. Việc không tìm được lối ra khác khiến hắn tin truyền tống trận trong Huyền Âm đỉnh là con đường rời khỏi nơi này.","theLucLienQuan":["Tiên Tuyển Tộc"],"nguon":["@c0762"]},{"id":"quang-truong-tien-tuyen-toc","name":"Quảng trường Tiên Tuyển tộc","cn":"","capDo":"khac","parentId":"khu-kien-truc-co-xua-cua-toc-tien-di-tien-tuyen","blurb":"Không gian nơi toàn bộ Tiên Tuyển tộc tụ tập quanh đài gỗ đặt Tháp Sơn hấp hối. Tại đây lão nhân công khai chân tướng tiên giới sụp đổ và ý chí phản kháng của toàn tộc bùng lên.","detail":"Quảng trường có đài gỗ rộng ba trượng, trên đó Tháp Sơn nằm trong tử khí do nô phù cắn trả. Đây là nơi lão nhân Tiên Tuyển tộc gọi Tháp Sơn là người phản kháng đầu tiên, chất vấn số phận nô bộc do tiên nhân an bài và nhận được xác nhận của Vương Lâm rằng tiên giới đã sụp đổ.","theLucLienQuan":["Tộc Tiên Tuyển"],"nguon":["@c0765"]},{"id":"hu-vo-toi-den-am-u","name":"Hư vô tối đen âm u","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian tối đen âm u nơi có trận pháp đỏ sậm như máu và quan tài pha lê chứa thi thể nam nhân bí ẩn, hé lộ cuối chương.","detail":"Vùng hư vô tối đen âm u, xuất hiện ở cuối chương. Bên trong có một trận pháp khổng lồ màu đỏ sậm như máu; hắc khí tràn qua trận pháp dung nhập vào chiếc quan tài pha lê ở trung tâm, nơi có thi thể nam nhân tuấn mỹ như đang ngủ say. Là địa điểm bí ẩn mới, chưa rõ liên hệ.","theLucLienQuan":[],"nguon":["@c0766"]},{"id":"te-dan-thong-dao-huyen-am-dinh","name":"Tế đàn thông đạo Huyền Âm đỉnh","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực có cửa lớn, thông đạo và Huyền Âm đỉnh; nơi Vương Lâm mở cửa, phá đỉnh và kích hoạt đường rời đi.","detail":"Tế đàn có cửa lớn mở bằng ấn ký mi tâm, dẫn vào thông đạo tận cùng là Huyền Âm đỉnh. Vương Lâm dùng tam diện tiểu kỳ màu tím chống âm thanh bén nhọn, Tháp Sơn phá vỡ Huyền Âm đỉnh; sau đó truyền tống trận nhỏ dưới đỉnh lộ ra, đưa Vương Lâm và Tiên Tuyển tộc rời đi.","theLucLienQuan":["Tộc Tiên Tuyển"],"nguon":["@c0766"]},{"id":"hu-vo-ngoai-tran-phap","name":"Hư vô ngoài trận pháp","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian hư vô nơi nam tử áo đen thủ hộ quan tài pha lê và trận pháp khổng lồ. Đây cũng là chiến trường giữa Vương Lâm với năm phân thân.","detail":"Hư vô ngoài trận pháp là khu vực Vương Lâm xuất hiện từ lốc xoáy năm màu, giao chiến với năm phân thân và lần theo thần thức tiến tới trận pháp. Nam tử áo đen ngồi thủ hộ quan tài trong vùng này trước khi bị lộ thân thể toàn xương trắng.","theLucLienQuan":["Tiên Tuyển Tộc"],"nguon":["@c0767"]},{"id":"loc-xoay-hao-quang-nam-mau","name":"Lốc xoáy hào quang năm màu","cn":"","capDo":"khac","parentId":"hu-vo-ngoai-tran-phap","blurb":"Điểm xuất hiện của Vương Lâm, Hứa Lập Quốc, Tháp Sơn và toàn bộ tộc nhân Tiên Tuyển Tộc. Từ đây Vương Lâm bắt đầu phát hiện phân thân áo lam đang bay tới.","detail":"Lốc xoáy hào quang năm màu mở ra trong hư vô, để nhóm Vương Lâm và tộc nhân Tiên Tuyển Tộc hiện thân. Sau khi bước ra, Vương Lâm dùng thần thức dò xét và phát hiện phân thân đầu tiên của nam tử áo đen.","theLucLienQuan":["Tiên Tuyển Tộc"],"nguon":["@c0767"]},{"id":"khu-vuc-tran-phap-va-quan-tai-pha-le","name":"Khu vực trận pháp và quan tài pha lê","cn":"","capDo":"khac","parentId":"hu-vo-ngoai-tran-phap","blurb":"Đích đến mà Vương Lâm tìm được sau khi nhận ra kế dẫn dụ của bốn phân thân. Nơi này có trận pháp khổng lồ, quan tài pha lê và nam tử áo đen thủ hộ.","detail":"Sau khi dừng truy kích bốn phân thân để tránh bị dẫn đi xa, Vương Lâm khoanh chân dùng thần thức tìm hướng rồi lao tới khu vực trận pháp. Tại đây hắn thấy trận pháp khổng lồ cùng quan tài pha lê phía trước, đồng thời phát hiện thân thể xương trắng của nam tử áo đen.","theLucLienQuan":[],"nguon":["@c0767"]},{"id":"la-thien-tay-vuc","name":"La Thiên Tây Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực sương mù sâu trong La Thiên, nơi U Minh Thú xuất hiện và Vương Lâm dẫn Tiên Tuyển tộc thoát ra ngoài.","detail":"Sau khi rời thế giới bên trong U Minh Thú, Vương Lâm cùng Tiên Tuyển tộc xuất hiện trong vùng sương mù La Thiên Tây Vực. Họ phi hành nhiều tháng, liên tục huyết chiến với mãnh thú trước khi xông ra tinh không.","theLucLienQuan":["Tiên Tuyển tộc"],"nguon":["@c0769"]},{"id":"dong-tam-tinh","name":"Đông Tâm Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu của Hướng gia thượng cổ tu chân, một trong các gia tộc ủng hộ Lôi Tiên Điện.","detail":"Đông Tâm Tinh được nêu là địa bàn của Hướng gia. Hướng gia trên tinh cầu này chủ động tìm Lôi Tiên Điện, cùng một thượng cổ gia tộc khác ủng hộ kế hoạch tiến quân Liên Minh Tinh Vực.","theLucLienQuan":["Đông Tâm Tinh Hướng gia","Lôi Tiên Điện"],"nguon":["@c0769"]},{"id":"u-minh-thu-dia-danh","name":"U Minh Thú","cn":"","capDo":"khac","parentId":"la-thien-tay-vuc","blurb":"Cự thú khổng lồ như chứa một thế giới trong thân, nơi Vương Lâm và Tiên Tuyển tộc từng bị truyền tống vào rồi rời ra qua trận pháp trong miệng.","detail":"U Minh Thú là sinh vật cổ xưa trong ký ức Đồ Ti, thân thể như có càn khôn bên trong. Chương này Vương Lâm xác nhận cự thú không mắt mở miệng cho họ rời khỏi không gian bên trong qua một tòa trận pháp.","theLucLienQuan":["Tiên Tuyển tộc"],"nguon":["@c0769"]},{"id":"huyen-tran-tinh","name":"Huyền Trần Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tay-vuc","blurb":"Huyền Trần Tinh là một tu chân tinh thuộc La Thiên Tây Vực. Nơi đây có linh lực không quá nồng nhưng cũng không kém, và là nơi ba tu sĩ Âm Hư nhận ra Vương Lâm dưới danh xưng Hứa Mộc.","detail":"Sau mười ngày tìm kiếm trong tinh không, Vương Lâm gặp Huyền Trần Tinh và bị ba tu sĩ Âm Hư từ tinh cầu bay ra hỏi lai lịch. Âu Dương Đàn tại đây nhận ra hình ảnh Hứa Mộc trong Thiên Khung Lệnh, sau đó dùng ngọc giản liên lạc báo tin cho Diêu tộc.","theLucLienQuan":["Huyền Trần Tinh ba tu sĩ Âm Hư","Diêu gia"],"nguon":["@c0770"]},{"id":"linh-minh-tinh","name":"Linh Minh tinh","cn":"","capDo":"tinh-cau","parentId":"tinh-khong","blurb":"Linh Minh tinh là nơi có gia tộc của một Âm Hư tu sĩ tham gia chặn Hứa Mộc. Khi thất thế, người này hứa gia tộc Linh Minh tinh sẽ rút khỏi xung đột với Diêu gia.","detail":"Địa danh được nhắc qua lời cầu xin của Âm Hư tu sĩ bỏ thân thể chạy nguyên thần. Hắn dùng danh nghĩa toàn bộ gia tộc Linh Minh tinh để xin không còn tham dự chuyện giữa Hứa Mộc và Diêu gia.","theLucLienQuan":["Gia tộc Linh Minh tinh"],"nguon":["@c0772"]},{"id":"la-thien-dong-vuc","name":"La Thiên Đông Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực thuộc La Thiên Tinh Vực, nơi Diêu gia hoạt động và Huyết Thần Tử tọa trấn.","detail":"La Thiên Đông Vực là khu vực gắn với Diêu gia trong chương này. Tại đây có tinh cầu đỏ như máu của Diêu gia, từ đường đặt linh bài tộc nhân, và Diêu Băng Vân được tôn xưng là Hàn Phượng, một trong tam Phượng của La Thiên Đông Vực.","theLucLienQuan":["Diêu gia","Tam Phượng La Thiên Đông Vực"],"nguon":["@c0773"]},{"id":"tinh-cau-do-nhu-mau-cua-dieu-gia","name":"Tinh cầu đỏ như máu của Diêu gia","cn":"","capDo":"tinh-cau","parentId":"la-thien-dong-vuc","blurb":"Tinh cầu của Diêu gia tại La Thiên Đông Vực, có từ đường lớn và linh bài tộc nhân.","detail":"Tinh cầu này mang sắc đỏ như máu, là nơi đặt từ đường của Diêu gia. Bên trong có trụ gỗ khắc chữ Diêu với sát khí lăng lệ, cùng các linh bài chứa nguyên lực, nơi Huyết Thần Tử chứng kiến linh bài của Diêu Trường Không nứt đôi.","theLucLienQuan":["Diêu gia","Huyết Thần Tử"],"nguon":["@c0773"]},{"id":"tu-duong-dieu-gia","name":"Từ đường Diêu gia","cn":"","capDo":"khac","parentId":"tinh-cau-do-nhu-mau-cua-dieu-gia","blurb":"Từ đường đặt linh bài của Diêu gia, nơi Huyết Thần Tử ngồi quan sát biến cố tộc nhân.","detail":"Từ đường Diêu gia nằm trên tinh cầu đỏ như máu của Diêu gia. Huyết Thần Tử khoanh chân ngồi trước các linh bài; khi Diêu Trường Không chết, một linh bài trong từ đường nứt đôi và tỏa ra bạch khí để lão thu lấy.","theLucLienQuan":["Diêu gia","Huyết Thần Tử"],"nguon":["@c0773"]},{"id":"han-bang-tinh","name":"Hàn Băng Tinh","cn":"","capDo":"khac","parentId":"la-thien-dong-vuc","blurb":"Cấm địa của Diêu gia, nơi Diêu Băng Vân từng bế quan tu Bế Thần Tiên thuật.","detail":"Hàn Băng Tinh là một cấm địa của Diêu gia. Diêu Băng Vân từng ở nơi này bế quan năm trăm năm để tu luyện Bế Thần Tiên thuật, cấm thuật yêu cầu tự phong bế thất khiếu và từng khiến nhiều tộc nhân Diêu gia chết khi tu luyện.","theLucLienQuan":["Diêu gia","Diêu Băng Vân"],"nguon":["@c0773"]},{"id":"tinh-cau-hoang-phe-noi-giao-la-thien-tay-vuc-va-bac-vuc","name":"Tinh cầu hoang phế nơi giao giữa La Thiên Tây Vực và Bắc Vực","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu hoang phế nằm nơi giao giữa La Thiên Tây Vực và La Thiên Bắc Vực. Đây là nơi Vương Lâm tạm ẩn chữa thương sau khi bỏ rơi Diêu Băng Vân trong cuộc truy đuổi bằng dung nhập thiên địa.","detail":"Tu chân tinh này không có linh lực và đầy hoang tàn. Vương Lâm chọn một thung lũng trên tinh cầu để thả Tôn Hồn Phiên, bố trí cấm chế, nuốt nguyên thần Âm Hư, tu bổ Tháp Sơn; ngay sau đó Diêu Băng Vân lần tới bên ngoài tinh cầu và hai bên giao chiến trong tinh không.","theLucLienQuan":["Diêu gia"],"nguon":["@c0774"]},{"id":"dai-ngan-ha-giua-la-thien-tay-vuc-va-bac-vuc","name":"Dải ngân hà giữa La Thiên Tây Vực và Bắc Vực","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc","blurb":"Vùng giao giới mà Vương Lâm muốn vượt qua để sang Bắc Vực.","detail":"Khu vực này bị nhiều tu sĩ tụ lại phong tỏa, khiến Vương Lâm không thể đơn giản thoát khỏi cuộc truy sát của Diêu gia và các gia tộc trợ chiến.","theLucLienQuan":["Diêu gia","Các tu chân gia tộc trợ giúp Diêu gia"],"nguon":["@c0775"]},{"id":"tu-chan-tinh-khong-ro-ten-dau-tien-bi-vuong-lam-do-sat","name":"Tu chân tinh không rõ tên đầu tiên bị Vương Lâm đồ sát","cn":"","capDo":"tinh-cau","parentId":"la-thien-tay-vuc","blurb":"Tu chân tinh đầu tiên bị Vương Lâm chọn làm nơi mở màn trả thù.","detail":"Nơi này không có tu sĩ trên Vấn Đỉnh đại viên mãn tọa trấn, khiến Vương Lâm suy đoán cao thủ đã đi tham gia truy sát. Hắn giết tu sĩ từ Anh Biến trở lên, không động tới phàm nhân và tu sĩ quá thấp.","theLucLienQuan":["Các tu chân gia tộc trợ giúp Diêu gia"],"nguon":["@c0775"]},{"id":"tu-chan-tinh-hoang-phe","name":"Tu chân tinh hoang phế","cn":"","capDo":"tinh-cau","parentId":"la-thien-tay-vuc","blurb":"Tinh cầu chết được Vương Lâm chọn làm nơi bố trí Cửu Tuyệt Tổn Thần Trận.","detail":"Tinh cầu không còn sinh mệnh, đầy hoang tàn, khe nứt và tử khí. Vương Lâm hạ lạc ấn khắp nơi rồi dụ đội truy sát phá hủy tinh cầu, khiến mảnh vỡ trở thành bộ phận của trận pháp.","theLucLienQuan":["Các tu chân gia tộc truy sát Hứa Mộc","Diêu gia"],"nguon":["@c0776"]},{"id":"giao-gioi-la-thien-tay-vuc-va-bac-vuc","name":"Giao giới La Thiên Tây Vực và Bắc Vực","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc","blurb":"Tuyến đường đoàn truy sát vượt qua khi Vương Lâm kéo họ từ Tây Vực sang Bắc Vực.","detail":"Khu vực chuyển tiếp giữa hai vực của La Thiên, đánh dấu việc cuộc truy sát rời khỏi Tây Vực và tiến vào Bắc Vực, nơi Vương Lâm có mục tiêu mới là Vọng Nguyệt.","theLucLienQuan":["Diêu gia","Các tu chân gia tộc khác"],"nguon":["@c0777"]},{"id":"la-van","name":"La Vân","cn":"","capDo":"khac","parentId":"la-thien-bac-vuc","blurb":"Khu vực trung tâm La Thiên Bắc Vực gần ngũ đại chủ tinh.","detail":"Vương Lâm xuất hiện tại La Vân, dùng thần thức tìm kiếm và xác nhận Vọng Nguyệt vẫn ở Bắc Vực, rồi đổi hướng về phía ngũ đại chủ tinh.","theLucLienQuan":[],"nguon":["@c0777"]},{"id":"ngu-dai-chu-tinh","name":"Ngũ đại chủ tinh","cn":"","capDo":"khac","parentId":"la-thien-bac-vuc","blurb":"Khu vực gần nơi Vọng Nguyệt hóa thành tinh cầu.","detail":"Sau khi xác nhận Vọng Nguyệt còn ở Bắc Vực, Vương Lâm hướng tới vùng gần ngũ đại chủ tinh để thực hiện kế hoạch mượn hung thú đối phó truy binh.","theLucLienQuan":[],"nguon":["@c0777"]},{"id":"tinh-cau-do-vong-nguyet-bien-thanh","name":"Tinh cầu do Vọng Nguyệt biến thành","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Cấm địa ở La Thiên Bắc Vực do Vọng Nguyệt hóa thành, được Vương Lâm dùng làm bẫy truy binh.","detail":"Tinh cầu bị màn sương đen bao phủ, không phải tu chân tinh bình thường mà là sinh mạng thể khổng lồ Vọng Nguyệt đang ngủ say. Vương Lâm tiến vào nơi này để dẫn Diêu gia và các gia tộc truy sát đối mặt hung vật.","theLucLienQuan":["Diêu gia","Các tu chân gia tộc khác"],"nguon":["@c0777"]},{"id":"cot-dinh-xuong-dau-cua-vong-nguyet","name":"Cốt đỉnh / xương đầu của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"co-the-vong-nguyet","blurb":"Vị trí nhạy cảm trong cơ thể Vọng Nguyệt mà Vương Lâm hướng tới.","detail":"Vương Lâm hướng về cốt đỉnh hay xương đầu vì biết đây là nơi nhạy cảm của Vọng Nguyệt, có thể dùng để kích thích con thú thức tỉnh nhanh hơn.","theLucLienQuan":[],"nguon":["@c0778"]},{"id":"man-suong-den-ben-ngoai-tinh-cau-vong-nguyet","name":"Màn sương đen bên ngoài tinh cầu Vọng Nguyệt","cn":"","capDo":"khac","parentId":"tinh-cau-do-vong-nguyet-bien-thanh","blurb":"Lớp sương bao quanh tinh cầu Vọng Nguyệt, cửa ngõ để tu sĩ tiến vào bề mặt hung thú.","detail":"Diêu Băng Vân, Diêu Vân Hải và nhiều tu sĩ xuyên qua màn sương này để vào bề mặt tinh cầu do Vọng Nguyệt biến thành, mở đầu việc nhiều người chìm vào cơ thể hung thú.","theLucLienQuan":["Diêu gia"],"nguon":["@c0778"]},{"id":"khong-gian-bun-dat-noi-co-vong-nguyet","name":"Không gian bùn đất nơi có Vọng Nguyệt","cn":"","capDo":"khac","parentId":"co-the-vong-nguyet","blurb":"Khu vực trong cơ thể Vọng Nguyệt nơi Vương Lâm và Diêu Băng Vân giao chiến.","detail":"Không gian này không thể thuấn di và bị ngăn cách sức mạnh thiên địa, gồm các tầng bùn đất và khe hở nơi nhiều con Vọng Nguyệt trăm trượng chui ra. Vương Lâm lợi dụng tiếng nổ trong khu vực này để dẫn dụ Vọng Nguyệt.","theLucLienQuan":["Diêu gia"],"nguon":["@c0779"]},{"id":"vung-giao-giua-xuong-cot-va-day-than-kinh-cua-vong-nguyet","name":"Vùng giao giữa xương cốt và dây thần kinh của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"tinh-cau-do-vong-nguyet-bien-thanh","blurb":"Khu vực sâu trong thân thể Vọng Nguyệt, nơi Vương Lâm chui vào qua khe hở cũ do nửa thanh xương từng bị rút ra.","detail":"Bên trong vùng này dày đặc tơ đỏ như mạng nhện. Vương Lâm tiến vào đây và dùng Trảm La Quyết chém đứt các sợi tơ, khiến toàn thân Vọng Nguyệt chấn động rồi dẫn tới thức tỉnh.","theLucLienQuan":[],"nguon":["@c0780"]},{"id":"khu-vuc-trong-co-the-vong-nguyet","name":"Khu vực trong cơ thể Vọng Nguyệt","cn":"","capDo":"khac","parentId":"tinh-cau-do-vong-nguyet-bien-thanh","blurb":"Không gian bên trong Vọng Nguyệt, nơi Diêu Băng Vân và nhiều tu sĩ bị mắc kẹt khi cự thú chấn động.","detail":"Tại đây, các tu sĩ Diêu gia và nhiều tu sĩ thuộc các tu chân gia tộc khác hoảng loạn muốn thoát lên mặt đất nhưng bị xúc tu phong tỏa. Pháp bảo và thần thông khó phát huy hiệu quả, có tu sĩ bị xúc tu nghiền nát thân thể và hấp thu nguyên thần.","theLucLienQuan":["Diêu gia","Các tu chân gia tộc khác"],"nguon":["@c0780"]},{"id":"vi-tri-cach-chien-truong-muoi-van-dam","name":"Vị trí cách chiến trường mười vạn dặm","cn":"","capDo":"khac","parentId":"la-thien-bac-vuc","blurb":"Nơi Viêm Lôi Tử, Hướng mỗ và lão già hồng bào đứng quan sát Vọng Nguyệt tàn sát.","detail":"Cách chiến trường mười vạn dặm, ba cường giả gồm Viêm Lôi Tử, Hướng mỗ và lão già hồng bào quan sát diễn biến Vọng Nguyệt tàn sát tu sĩ, đồng thời bàn về kế hoạch nhiều năm nhắm vào Nguyệt Thú và cuộc chiến La Thiên với Liên Minh.","theLucLienQuan":["La Thiên Tinh Vực","Đông Lâm Tinh"],"nguon":["@c0781"]},{"id":"loi-tien-dien-dia-danh","name":"Lôi Tiên Điện","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc","blurb":"Địa điểm quyền lực của La Thiên, nơi có mật thất chứa viễn cổ trận pháp.","detail":"Sau khi phân thân bị Cổ Thần chỉ đánh tan, bản thể Viêm Lôi Tử, lão già họ Hướng và Công Tôn đồng thời tỉnh lại tại mật thất trong Lôi Tiên Điện, rồi bàn kế hoạch tập hợp thêm người bắt giữ Vọng Nguyệt.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0782"]},{"id":"tu-chan-tinh-tai-la-thien-bac-vuc","name":"Tu chân tinh tại La Thiên Bắc Vực","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Các tu chân tinh trong La Thiên Bắc Vực chịu ảnh hưởng từ va chạm giữa Cổ Thần chỉ và ba phân thân đại năng.","detail":"Khi Cổ Thần chỉ va chạm với viêm long, hồng kiếm và hắc ưng, âm thanh thần niệm rung động lan xa, khiến tu sĩ trên nhiều tu chân tinh trong khu vực cảm nhận được chấn động.","theLucLienQuan":["La Thiên Tinh Vực"],"nguon":["@c0782"]},{"id":"nao-bo-cua-vong-nguyet","name":"Não bộ của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"vong-nguyet","blurb":"Lốc xoáy âm hàn sâu trong cơ thể Vọng Nguyệt, được xác định là não bộ và nơi sinh sống của con Vọng Nguyệt vạn trượng.","detail":"Khu vực này chứa bí mật xúc tu hút sinh mạng: vô số xúc tu từ hư không kéo ra quấn lấy đại đỉnh của Tham Lang và những người bị nuốt vào, hấp thu sinh cơ của họ. Vương Lâm bị phun vào đây sau khi bị Vọng Nguyệt vạn trượng nuốt.","theLucLienQuan":[],"nguon":["@c0783"]},{"id":"tan-linh-tinh","name":"Tán Linh tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu được nhắc trong kế hoạch trước đó của Vương Lâm.","detail":"Vương Lâm từng dự định đưa người của tộc Tiên Tuyển tới Tán Linh tinh, sau đó tìm Lý Nguyên để học Phá Diệt Tâm Cấm rồi nghỉ ngơi.","theLucLienQuan":["Tộc Tiên Tuyển"],"nguon":["@c0783"]}]};
